import type { Drill } from "./types";

// Doctor / senior drills, keyed by module slug — 25 per module.
// Pitched at a chief of service / medical director / hospital executive: board
// narratives, budget and staffing cases, protocol rollouts, crisis
// communications, regulator- and press-adjacent statements. Merged into course.ts.
export const DOCTOR_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-doc-senior-01","level":"senior","profession":"doctor","title":"The buried board headline","scenario":"Your quarterly report to the hospital board opens with two paragraphs on the fast-track pilot's methodology. The actual news: ED wait times fell by a third, the biggest improvement in five years.","task":"Write a 2-3 sentence report opening that leads with the result.","tips":["Sentence one is the headline number, not the project history.","Boards read the first line and skim the rest — put the win there.","Methodology becomes supporting detail below."],"focus":["structure","impact"],"placeholder":"ED median wait time fell 34% this quarter —"},
    {"id":"lead-doc-senior-02","level":"senior","profession":"doctor","title":"The locum funding ask","scenario":"Two hospitalists resigned this month and January has uncovered shifts. You need the CEO to approve emergency locum funding this week, but your draft email opens with a recap of the resignation timeline.","task":"Write an email opening that puts the ask and the deadline in sentence one.","tips":["Lead with what you need approved and by when.","The resignation story is context — two lines, after the ask.","Name the consequence of waiting in one clause."],"focus":["clarity","impact"],"placeholder":"I need approval for emergency locum funding by Friday —"},
    {"id":"lead-doc-senior-03","level":"senior","profession":"doctor","title":"The protocol memo that opens with history","scenario":"The new sepsis screening protocol goes live on all inpatient units Monday. Your draft memo to the medical staff spends its first paragraph on the eight months of committee work that produced it.","task":"Write a 2-3 sentence memo opening that leads with what changes and when.","tips":["First sentence: the new requirement and the effective date.","Clinicians triage memos in seconds — earn the read immediately.","The committee's journey belongs at the bottom, if anywhere."],"focus":["clarity","structure"]},
    {"id":"lead-doc-senior-04","level":"senior","profession":"doctor","title":"The incident notification","scenario":"A medication dosing error occurred overnight on 4 West. The patient is stable and the family has been informed. You must notify the COO, but your draft walks through the event chronologically from shift change onward.","task":"Write a 2-3 sentence notification that leads with what happened and the current status.","tips":["First line: the event, the severity, the patient's status now.","Executives need the bottom line before the timeline.","Name the immediate next step so no one has to ask."],"focus":["clarity","impact"],"placeholder":"Overnight medication error on 4 West — patient is stable and the family has been informed."},
    {"id":"lead-doc-senior-05","level":"senior","profession":"doctor","title":"The variance email that hides the number","scenario":"Your department is $410K over budget on agency nursing, driven by ICU vacancies. Your draft to the CFO opens with three sentences about how hard the labor market has been this year.","task":"Write an email opening that states the number and its driver in sentence one.","tips":["Lead with the figure — the CFO will find it anyway.","Name the single biggest driver in the same breath.","Save the market commentary; it reads as excuse when it comes first."],"focus":["precision","clarity"]},
    {"id":"lead-doc-senior-06","level":"senior","profession":"doctor","title":"One quarter, one headline","scenario":"This quarter held an ED expansion approval, an accreditation survey visit, and a nursing turnover spike. Your board pre-read needs one governing opening line, but your draft lists all three events with equal weight.","task":"Write the single opening sentence of the pre-read that carries the one takeaway you want the board to hold.","tips":["Decide the headline before you write — everything else supports it.","If everything is equally important, nothing is.","A board member should be able to repeat your first sentence to a colleague."],"focus":["structure","impact"]},
    {"id":"lead-doc-senior-07","level":"senior","profession":"doctor","title":"The divert decision","scenario":"Nineteen admitted patients are boarding in the ED and the day is getting worse. You need the COO to either authorize opening the flex unit or accept going on ambulance divert — today. Your draft message recounts the morning's census first.","task":"Write a message whose first sentence is the decision you need and the deadline.","tips":["Lead with the choice and the clock, not the census story.","Two options, clearly named, one sentence each.","State your recommendation so the decision is easy to make."],"focus":["clarity","impact"],"placeholder":"I need a decision by noon: open the flex unit or go on divert."},
    {"id":"lead-doc-senior-08","level":"senior","profession":"doctor","title":"The consolidation announcement","scenario":"The decision is made: the two westside outpatient clinics will merge into one location in the fall. Staff have heard rumors for weeks. Your town hall opening is drafted as a tour of the strategic review that led here.","task":"Write the first two sentences of the town hall that state the decision plainly.","tips":["People came to hear the decision — give it in sentence one.","Rumor thrives in the gap before the point; close it fast.","The rationale matters, but only after the news lands."],"focus":["clarity","audience"]},
    {"id":"lead-doc-senior-09","level":"senior","profession":"doctor","title":"The above-band offer","scenario":"Your top cardiology candidate has a competing offer that expires Friday. You need the CEO to approve an offer above the salary band. Your draft opens with the recruitment history and the search firm's process.","task":"Write a 2-3 sentence request that leads with the approval you need and the deadline.","tips":["Ask first: the approval, the amount, the date.","One sentence on why this candidate justifies the exception.","The search history is available on request — don't lead with it."],"focus":["clarity","impact"],"placeholder":"I'm asking you to approve an above-band offer for our cardiology candidate by Thursday —"},
    {"id":"lead-doc-senior-10","level":"senior","profession":"doctor","title":"The readmissions win","scenario":"Thirty-day readmissions are down 2.1 percentage points since the discharge-call program launched. Your update to the quality committee is drafted as a walkthrough of the program's staffing model before the result appears.","task":"Write a 1-2 sentence committee update that leads with the result.","tips":["The number is the news — say it first.","Attribute the change carefully in the same sentence, not three paragraphs later.","Program mechanics are for the appendix."],"focus":["structure","precision"]},
    {"id":"lead-doc-senior-11","level":"senior","profession":"doctor","title":"The accreditation verdict","scenario":"The survey is over: full accreditation, with two minor findings that have a 60-day correction window. Your note to the board is drafted as a day-by-day account of the survey visit.","task":"Write a 2-3 sentence board note that leads with the verdict.","tips":["Verdict in sentence one: full accreditation.","The two findings and their deadline are sentence two — don't hide them.","The survey diary is not what the board needs."],"focus":["clarity","structure"]},
    {"id":"lead-doc-senior-12","level":"senior","profession":"doctor","title":"The outbreak action notice","scenario":"A norovirus cluster has emerged on 5 East. Symptomatic patients must be cohorted starting tonight and visitor restrictions begin tomorrow morning. Your draft to unit managers opens with a summary of the epidemiology.","task":"Write a notice that puts the required actions and their start times in the first two sentences.","tips":["Managers need the action first: what to do, starting when.","One line of context is enough — this is an instruction, not a briefing.","End with who to call with questions."],"focus":["clarity","impact"],"placeholder":"Effective tonight: cohort all symptomatic patients on 5 East. Visitor restrictions begin 7am tomorrow."},
    {"id":"lead-doc-senior-13","level":"senior","profession":"doctor","title":"The board chair's yes/no","scenario":"The board chair emails one question: will the hospital have enough beds for flu season? You know the answer is yes, provided the flex unit funding holds and agency contracts are signed. Your draft explains the modeling before answering.","task":"Write a reply that answers yes or no in the first word or two, then gives the conditions.","tips":["Answer the question asked, immediately.","Conditions follow the answer — they don't replace it.","A direct answer with caveats reads as command of the facts."],"focus":["clarity","concision"],"placeholder":"Yes — on two conditions:"},
    {"id":"lead-doc-senior-14","level":"senior","profession":"doctor","title":"The weekend handoff","scenario":"You're handing the weekend to the on-call administrator. One live issue matters: ICU night shift is short two nurses Saturday and the agency confirmations are still pending. Your draft note opens with a calm recap of the routine items.","task":"Write a handoff note that leads with the one live issue and what to do about it.","tips":["If they read one line, it must be the Saturday gap.","Say what action to take and the trigger for taking it.","Routine items go below the fold."],"focus":["structure","precision"]},
    {"id":"lead-doc-senior-15","level":"senior","profession":"doctor","title":"The compliance review deadline","scenario":"The new inter-facility transfer agreement must be reviewed by compliance before Thursday's board meeting, or approval slips a month. Your draft to the compliance director spends a paragraph on the agreement's background first.","task":"Write a message that puts the request and the Friday-before-board deadline in sentence one.","tips":["Lead with the ask and the date, plus what slips if it's missed.","Attach the document; don't summarize it in the ask.","Offer a call if the deadline is a problem — but ask first."],"focus":["clarity","impact"]},
    {"id":"lead-doc-senior-16","level":"senior","profession":"doctor","title":"The downtime all-clear","scenario":"The EHR is back after a four-hour outage. Orders are flowing and lab results are catching up over the next hour. Your all-staff draft opens by re-narrating the outage everyone just lived through.","task":"Write a 2-3 sentence all-clear that leads with the restored status.","tips":["First line: the system is up, as of when.","Then the one thing still catching up and its ETA.","No one needs the outage recap — they were there."],"focus":["clarity","concision"],"placeholder":"The EHR is back up as of 2:40pm —"},
    {"id":"lead-doc-senior-17","level":"senior","profession":"doctor","title":"The decision buried in minutes","scenario":"The medical executive committee voted to standardize hip implants to two vendors starting next quarter. Your recap email to department chairs is drafted like meeting minutes — attendance, agenda, discussion — with the decision in paragraph four.","task":"Rewrite the recap so the decision leads, then the effective date and the vote.","tips":["Lead with what was decided and when it takes effect.","The vote count is one clause, not a paragraph.","Chairs act on decisions, not on minutes."],"focus":["structure","clarity"]},
    {"id":"lead-doc-senior-18","level":"senior","profession":"doctor","title":"The MRI suite slip","scenario":"The new MRI suite's opening slips from March 3 to mid-April because the vendor's installation team is delayed. The CEO is expecting a March ribbon-cutting with donors invited. Your draft eases in with the construction status.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that's what changes the CEO's plans.","One sentence on the cause; no vendor blame spiral.","Offer the revised donor-event options in the same message."],"focus":["clarity","impact"]},
    {"id":"lead-doc-senior-19","level":"senior","profession":"doctor","title":"The monitoring contract pick","scenario":"Two vendors bid on the patient-monitoring replacement. You've scored both and have a clear pick, but your memo to the capital committee presents four pages of comparison before the recommendation.","task":"Rewrite the memo opening so the recommendation comes first, with the deciding reason.","tips":["State your pick and the single deciding factor in sentence one.","The comparison matrix is evidence, not the message.","A committee that knows your answer reads the analysis faster."],"focus":["structure","clarity"],"placeholder":"Recommend we award the monitoring contract to Vendor B —"},
    {"id":"lead-doc-senior-20","level":"senior","profession":"doctor","title":"The nomination request","scenario":"Every department chair must name a quality lead by the 15th so the safety program can launch on schedule. Your draft to the chairs opens with two paragraphs about the program's goals.","task":"Write a message that leads with the ask and the date, then gives one sentence of context.","tips":["Sentence one: what you need from each chair, by when.","Busy chairs skim — make the action unmissable.","Link the program details rather than restating them."],"focus":["clarity","concision"]},
    {"id":"lead-doc-senior-21","level":"senior","profession":"doctor","title":"The foundation update","scenario":"The donor-funded portable ultrasound units are in service: 300 bedside scans in the first month. Your update to the foundation is drafted as a procurement chronology — order, delivery, training — before the outcome appears.","task":"Write a 2-3 sentence update that leads with the outcome the gift produced.","tips":["Donors funded an outcome, not a procurement process — lead with it.","One concrete number beats three adjectives.","Close with what the impact makes possible next."],"focus":["impact","audience"]},
    {"id":"lead-doc-senior-22","level":"senior","profession":"doctor","title":"The leadership announcement","scenario":"Your division chief of ten years is stepping down June 30, and an interim has been named. Your all-staff draft opens with a long tribute before the actual news, so early readers can't tell what happened.","task":"Write the first two sentences of the announcement: the news first, then the transition.","tips":["News in sentence one: who is stepping down and when.","The interim's name is sentence two — people's first question is continuity.","The tribute follows; it lands better after clarity."],"focus":["clarity","structure"]},
    {"id":"lead-doc-senior-23","level":"senior","profession":"doctor","title":"The transfer-delay escalation","scenario":"Transfers to your tertiary partner are averaging nine hours against a four-hour target, and two delayed cases this month had poor outcomes under review. You're writing the network executive to request a dedicated transfer coordinator. Your draft opens with the history of the partnership.","task":"Write an opening that leads with the ask, backed by the single most important number.","tips":["The ask and the nine-versus-four number belong in sentence one.","Cases under review add weight — one sentence, stated carefully.","History reads as throat-clearing when the ask is urgent."],"focus":["impact","precision"],"placeholder":"I'm requesting a dedicated transfer coordinator: our transfers are averaging 9 hours against a 4-hour target."},
    {"id":"lead-doc-senior-24","level":"senior","profession":"doctor","title":"The agency contract clock","scenario":"The nurse staffing agency contract must be renewed by month end to hold current rates; after that, rates rise 12%. Your note to the CFO is drafted as an even-handed summary of the vendor relationship.","task":"Write a 2-3 sentence note that leads with the decision needed and the cost of waiting.","tips":["Decision, deadline, and the 12% consequence — all in the first sentence if you can.","Your recommendation should be visible, not implied.","Vendor relationship history is a footnote here."],"focus":["clarity","precision"]},
    {"id":"lead-doc-senior-25","level":"senior","profession":"doctor","title":"The councilmember's question","scenario":"A city councilmember emails asking whether weekend urgent-care hours are being cut, citing a constituent rumor. In fact, weekend hours are being extended in the fall. Your draft, routed through community relations, opens with background on the clinic network.","task":"Write a 2-sentence reply that answers the question first.","tips":["Answer in word one: no. Then say what's actually happening.","A public official will quote your first sentence — make it the answer.","Offer a follow-up contact rather than padding the reply."],"focus":["clarity","audience"],"placeholder":"No — weekend urgent-care hours are expanding, not shrinking."}
  ],
  "start-with-the-audience": [
    {"id":"audience-doc-senior-01","level":"senior","profession":"doctor","title":"The EHR migration, for the board","scenario":"You're briefing the board on the EHR migration. Your draft talks about interface engines, data mapping, and cutover sequencing. Board members care about three things: patient safety during the switch, cost, and how long the disruption lasts.","task":"Rewrite the briefing opening in 3-4 sentences framed around what the board actually weighs.","tips":["Translate every technical step into risk, cost, or duration.","Name what could go wrong and what protects against it.","If a sentence needs IT vocabulary to work, it isn't for this audience."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-02","level":"senior","profession":"doctor","title":"One metric, two rooms","scenario":"The case-mix index dipped this quarter. To the CFO that's a revenue signal; to your physicians it sounds like an accusation about their documentation. You're writing the physician version and keep drafting it in finance language.","task":"Write a 3-4 sentence note to the medical staff that frames the dip in terms of their work, not the ledger.","tips":["Pick the one behavior you're asking of physicians and lead with it.","Explain the metric in one plain clause, then drop the jargon.","Avoid any sentence that reads as blame from finance."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-03","level":"senior","profession":"doctor","title":"The visitor policy, for families","scenario":"The new visitor policy limits overnight visitors to one per patient. Your draft for the hospital website is written like the internal policy document — clauses, exceptions, definitions. A worried spouse will read it at midnight on a phone.","task":"Write a 3-4 sentence public version a stressed family member can grasp in one read.","tips":["Lead with what a visitor can do, not with the restriction's rationale.","One sentence for the rule, one for the main exception, one for who to ask.","Cut every word a policy lawyer added."],"focus":["audience","concision"],"placeholder":"One support person can stay overnight with each patient."},
    {"id":"audience-doc-senior-04","level":"senior","profession":"doctor","title":"The staffing ratio, in dollars","scenario":"You want an improved nurse-to-patient ratio on the medical floors. Your case is written in safety language — acuity, missed care, burnout. The CFO who must fund it thinks in turnover cost, agency spend, and length of stay.","task":"Write a 3-4 sentence version of the case in the CFO's terms.","tips":["Convert safety benefits into the line items they move.","Use the CFO's own cost categories: agency, turnover, LOS.","Keep one human sentence — but make the money case carry the ask."],"focus":["audience","precision"],"placeholder":"The ratio change pays for itself through two lines you already track:"},
    {"id":"audience-doc-senior-05","level":"senior","profession":"doctor","title":"Why we go on divert","scenario":"A board member asks why the hospital keeps going on ambulance divert. Your instinct is to explain boarding, bed turnover, and discharge bottlenecks in operational vocabulary. The board member needs a causal chain a layperson can follow.","task":"Write a 3-4 sentence plain-language explanation of the divert pattern.","tips":["Build the chain step by step: full beds upstairs means ambulances wait downstairs.","One number makes it real; five make it a dashboard.","End with what would break the chain — that's the governance question."],"focus":["audience","structure"]},
    {"id":"audience-doc-senior-06","level":"senior","profession":"doctor","title":"The welcome that assumes too much","scenario":"You're writing the orientation message for the incoming resident class. Your draft references \"the usual escalation path,\" \"the Tuesday huddle,\" and \"the portal\" — shorthand no one outside the building understands yet.","task":"Rewrite a 4-5 sentence welcome that assumes zero institutional knowledge.","tips":["Spell out every piece of shorthand or cut it.","Tell them the one thing to do on day one, not the whole system.","Read it as someone who parked in the wrong lot this morning."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-07","level":"senior","profession":"doctor","title":"Briefing the press team","scenario":"A local reporter is asking about weekend capacity strain. The comms team needs a briefing note from you they can work from. Your draft is written for clinicians — census percentages, boarding hours, staffing matrices.","task":"Write a 3-4 sentence briefing note in language a reporter's readers would understand.","tips":["Translate metrics into what a patient would experience.","Give comms the one sentence you'd be comfortable seeing quoted.","Flag clearly what is fact versus what is still being verified."],"focus":["audience","precision"]},
    {"id":"audience-doc-senior-08","level":"senior","profession":"doctor","title":"Throughput, for the front desk","scenario":"The patient-flow initiative changes how registration prioritizes arrivals. Your draft memo to front-desk staff explains the whole initiative — strategy, metrics, executive sponsors — when they need to know what changes at their window on Monday.","task":"Write a 3-4 sentence version for registration staff focused on what they do differently.","tips":["Their question is: what changes for me, starting when?","Strategy context is one sentence, not four paragraphs.","Name who to ask when the new process gets confusing."],"focus":["audience","clarity"],"placeholder":"Starting Monday, one thing changes at check-in:"},
    {"id":"audience-doc-senior-09","level":"senior","profession":"doctor","title":"Patient scores, for physicians","scenario":"Patient-experience scores are in, and you'll present them at the medical staff meeting. Your draft reads like the survey vendor's report — percentiles, composites, top-box rates. Physicians will tune out anything that doesn't connect to their practice.","task":"Write a 3-4 sentence framing that tells physicians what the scores mean for them specifically.","tips":["Lead with the one behavior the data ties to their day.","Translate percentile-speak into 'what patients said about us'.","Respect their skepticism: acknowledge what surveys can't measure."],"focus":["audience","impact"]},
    {"id":"audience-doc-senior-10","level":"senior","profession":"doctor","title":"The altitude check","scenario":"Your memo to department chairs about next year's priorities has drifted into unit-level detail — shift patterns, room assignments, order-set tweaks. Chairs operate a level up: they need direction they can translate for their own departments.","task":"Rewrite the memo's core message in 3-4 sentences at chair altitude.","tips":["State the priority and the outcome expected — let chairs choose tactics.","If a sentence names a specific room or shift, it's too low.","Give chairs language they can reuse with their teams."],"focus":["audience","structure"]},
    {"id":"audience-doc-senior-11","level":"senior","profession":"doctor","title":"Telehealth, for the patient council","scenario":"You're presenting the telehealth expansion to the patient advisory council, whose members skew older and are wary of losing in-person visits. Your slides were built for the strategy committee — adoption curves, visit-mix targets.","task":"Write a 3-4 sentence opening for the council that addresses their actual concern first.","tips":["Say plainly what does not change: in-person visits remain.","Frame telehealth as an added option, in concrete situations they'd recognize.","Retire the adoption-curve vocabulary entirely."],"focus":["audience","clarity"],"placeholder":"Nothing about your ability to see your doctor in person is changing."},
    {"id":"audience-doc-senior-12","level":"senior","profession":"doctor","title":"The payer change, for clinicians","scenario":"A major insurer changed its prior-authorization rules. The contracting team's summary is written in payer language — CPT groupings, utilization review tiers. Your physicians need to know which of their orders now require an extra step.","task":"Write a 3-4 sentence notice telling clinicians exactly what changes in their workflow.","tips":["Lead with the categories of orders affected, in clinical terms.","Say what to do differently and where the request goes.","Keep the contract mechanics out — they can't act on them."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-13","level":"senior","profession":"doctor","title":"Two audiences, one broken memo","scenario":"Your draft about the service-line reorganization tries to reassure staff and impress the board in the same document. It does neither: staff find it corporate, the board finds it defensive. You must pick a primary audience and rewrite.","task":"Choose the staff as your audience and write the 3-4 sentence core message for them alone.","tips":["One document, one primary reader — the other gets their own version.","Staff want to know: my job, my team, my location.","Cut every sentence performing for the board."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-14","level":"senior","profession":"doctor","title":"The research partnership, for nurses","scenario":"The hospital signed a clinical research partnership with the university. Your announcement draft dwells on institutional prestige and grant volume. Nursing staff want to know one thing: what does this mean for how we work on the units?","task":"Write a 3-4 sentence announcement for nursing staff centered on their stake.","tips":["Answer their real question first: what changes on the unit, if anything.","Name the concrete touchpoint: study coordinators, consent workflows, extra training.","Prestige is a closing line, not an opening."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-15","level":"senior","profession":"doctor","title":"Downtime procedures, minus the jargon","scenario":"IT drafted the ransomware downtime procedure notice: 'initiate downtime workflows per BC/DR runbook upon declaration.' Clinical staff reading it won't know what to physically do when screens lock.","task":"Rewrite the core instruction in 3-4 sentences a night-shift nurse can act on immediately.","tips":["Concrete actions: where the paper forms are, who declares downtime, who to call.","One instruction per sentence.","Test it: could someone follow this at 3am, mid-crisis, without asking IT?"],"focus":["audience","clarity"],"placeholder":"If your screen locks and won't restore, do three things:"},
    {"id":"audience-doc-senior-16","level":"senior","profession":"doctor","title":"The recruitment pitch that misses","scenario":"You're emailing a fellowship-trained surgeon you want to recruit. Your draft leads with the hospital's awards and expansion plans. Candidates at her level choose on call burden, OR access, team quality, and partnership path.","task":"Rewrite the pitch opening in 3-4 sentences around what she is actually weighing.","tips":["Lead with the two things her current job likely lacks.","Awards are wallpaper; specifics about her week are the pitch.","One genuine sentence about the team beats a paragraph of superlatives."],"focus":["audience","impact"]},
    {"id":"audience-doc-senior-17","level":"senior","profession":"doctor","title":"The budget cut, without the spreadsheet","scenario":"Next year's department budget is 4% smaller. Your draft to staff explains contribution margins and allocation methodology. Staff hear only one question in their heads: does this mean layoffs?","task":"Write a 3-4 sentence message that answers the human question first, then the practical changes.","tips":["Address the layoff question directly — silence on it drowns everything else.","Translate 4% into the two or three visible changes people will notice.","Finance methodology convinces no one who is worried."],"focus":["audience","clarity"],"placeholder":"No positions are being eliminated. Here is what does change:"},
    {"id":"audience-doc-senior-18","level":"senior","profession":"doctor","title":"The imaging case, in CFO terms","scenario":"You want the new CT scanner. Your draft argues image quality and diagnostic confidence — real benefits the CFO can't book. The financial case is there: shorter scan times mean more studies per day and fewer send-outs.","task":"Write a 3-4 sentence version of the case that leads with the operational and financial gain.","tips":["Lead with throughput and recaptured send-out volume.","Keep one clinical-quality sentence — it's real, just not the lead for this reader.","Give the payback estimate even if rough; name it as rough."],"focus":["audience","precision"]},
    {"id":"audience-doc-senior-19","level":"senior","profession":"doctor","title":"Near-miss reporting, for governance","scenario":"The board's quality committee asked how the hospital learns from near-misses. Your draft is full of internal vocabulary — huddles, RCAs, tiered escalation. Lay board members need the system explained as a system, not as acronyms.","task":"Write a 3-4 sentence plain-language explanation of how a near-miss becomes a fix.","tips":["Walk one imaginary near-miss through the pipeline, step by step.","Each acronym you keep must be defined in three words or cut.","End with how the board would know the system is working."],"focus":["audience","structure"]},
    {"id":"audience-doc-senior-20","level":"senior","profession":"doctor","title":"Survey prep, for every role","scenario":"Accreditation surveyors arrive in three weeks. Your all-staff draft lists thirty standards. The environmental services team, the pharmacy techs, and the unit clerks each need to know their two or three things — not all thirty.","task":"Write the 3-4 sentence version for environmental services staff specifically.","tips":["Name only the practices a surveyor would check in their work.","Frame it as 'what you already do right, keep doing visibly'.","Anxiety drops when the list is short and theirs."],"focus":["audience","concision"]},
    {"id":"audience-doc-senior-21","level":"senior","profession":"doctor","title":"The NICU case, for donors","scenario":"The foundation dinner is Thursday and you're making the case for the NICU expansion. Your draft cites bed counts, acuity levels, and transfer volumes. Donors give to outcomes they can picture, not to capacity metrics.","task":"Write a 3-4 sentence case for support in human terms, without a single acronym.","tips":["Start with what a family experiences when the unit is full.","Turn 'transfer volume' into 'babies cared for an hour from home'.","One statistic, chosen for the picture it paints."],"focus":["audience","impact"],"placeholder":"Last year, forty newborn babies had to be moved to hospitals an hour away —"},
    {"id":"audience-doc-senior-22","level":"senior","profession":"doctor","title":"The call-schedule change","scenario":"The revised call schedule adds one weekend per quarter for most physicians. Your draft explains the coverage math at length. Every physician reading it will scan for two things: how many more weekends, and what they get back.","task":"Write a 3-4 sentence notice that answers their two real questions immediately.","tips":["Numbers first: one additional weekend per quarter, starting March.","Name the offset — comp time, stipend, or reduced weekday call — in sentence two.","The coverage math goes in an appendix for the few who want it."],"focus":["audience","precision"]},
    {"id":"audience-doc-senior-23","level":"senior","profession":"doctor","title":"The union briefing","scenario":"You're meeting the nurses' union rep about the float-pool restructure. Your talking points are written in management language — flexibility, utilization, efficiency. The rep hears those words as code for doing more with less.","task":"Write 3-4 sentences of talking points framed in workload and safety terms.","tips":["Lead with what stays protected: ratios, scheduling notice, unit seniority.","Replace 'flexibility' with the specific scenario it solves.","Concede plainly what gets harder — credibility buys the rest."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-24","level":"senior","profession":"doctor","title":"The trial, for the local paper","scenario":"Comms wants a paragraph from you about the new clinical-trial partnership for the community paper. Your draft reads like the study protocol — enrollment criteria, endpoints, phases. Readers want to know what it could mean for someone they love.","task":"Write a 3-4 sentence paragraph for a general reader.","tips":["Lead with the condition studied and who might benefit locally.","Say honestly that trials are studies, not guaranteed treatments.","Every remaining technical term needs a plain-word neighbor."],"focus":["audience","clarity"]},
    {"id":"audience-doc-senior-25","level":"senior","profession":"doctor","title":"The quick read that isn't","scenario":"The CEO asked for 'a quick read' on ED performance before her board call in an hour. You have a three-page draft with unit-level tables. She needs four sentences she can absorb between meetings.","task":"Write the 4-sentence version: status, the one number that matters, the risk, the ask.","tips":["Honor the request's length — 'quick read' is a spec, not a pleasantry.","Choose the single number she'd repeat on the board call.","If there's no ask, say 'no action needed' — that's information too."],"focus":["audience","concision"],"placeholder":"ED performance is stable and slightly improving."}
  ],
  "structure-that-carries": [
    {"id":"structure-doc-senior-01","level":"senior","profession":"doctor","title":"One idea over three buckets","scenario":"Your board presentation on the year's quality performance is a list of eleven metrics in no particular order. The board can't tell what story the numbers add up to, and the discussion wanders.","task":"Write a governing sentence plus three bucket headings that organize the eleven metrics into one argument.","tips":["Name the single idea the whole slide proves, then group under it.","Three buckets maximum — safety, experience, efficiency, for example.","Every metric must fit one bucket; if it fits none, it's not for the board."],"focus":["structure","clarity"],"placeholder":"Our quality gains this year came from three shifts:"},
    {"id":"structure-doc-senior-02","level":"senior","profession":"doctor","title":"SCQA for the staffing case","scenario":"You're opening a written case for expanded overnight pharmacy coverage. Your draft jumps straight to the request. The reader needs the situation and the problem before the ask lands.","task":"Write a 4-sentence opening using situation, complication, question, answer.","tips":["Situation: the shared, uncontested fact. Complication: what changed or broke.","The question is the one the reader is now asking in their head.","Your answer to that question is the ask — and the rest of the case supports it."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-03","level":"senior","profession":"doctor","title":"PREP under the board's eye","scenario":"At the board meeting, a director asks whether the hospital is prepared for the next surge. You tend to ramble through history when put on the spot. You want a spoken answer with a spine.","task":"Draft a spoken answer using point, reason, example, point — 4-5 sentences.","tips":["Open with your one-line point: yes, with two named gaps.","Give the reason, then one concrete example that proves it.","Close by restating the point so it's the last thing they hear."],"focus":["structure","impact"]},
    {"id":"structure-doc-senior-04","level":"senior","profession":"doctor","title":"The messy risk list","scenario":"Your enterprise-risk update to the board is a flat list of fourteen items — cyber, staffing, a roof leak, a lawsuit, supply shortages — in the order they occurred to you. The board can't prioritize.","task":"Group the fourteen items into 3-4 named categories and write the category headings with a one-line framing for each.","tips":["Group by kind of risk or by who owns the response — pick one axis.","Order the categories by severity, not by chronology.","A good grouping makes the board's next question obvious."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-05","level":"senior","profession":"doctor","title":"The rollout with no sequence","scenario":"Your memo announcing the new discharge protocol lists a dozen changes as one undifferentiated block. Unit leaders can't tell what happens first, what's optional, or what needs training.","task":"Restructure the changes into a phased sequence — before launch, week one, ongoing — with a heading for each phase.","tips":["Time is the natural structure for a rollout: what, then what, then what.","Separate the mandatory from the recommended explicitly.","Each phase should end with who owns it."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-06","level":"senior","profession":"doctor","title":"The three reasons, not seven","scenario":"You're arguing to close the underused inpatient rehab unit. Your draft lists seven reasons of wildly uneven weight, so the strong ones drown among the weak.","task":"Choose the three strongest reasons and write them as three parallel, ordered points.","tips":["Cut the weak reasons — they dilute, they don't add.","Order the three by strength, strongest first.","Parallel construction signals you've thought in categories, not just piled points."],"focus":["structure","precision"]},
    {"id":"structure-doc-senior-07","level":"senior","profession":"doctor","title":"SCQA for a budget overrun","scenario":"You must explain to the finance committee why cardiology ran over budget. Your draft opens defensively with justifications. It needs a clean situation-complication-question-answer spine.","task":"Write a 4-5 sentence explanation structured as SCQA.","tips":["Situation: the budget as approved. Complication: the volume surge that hit it.","The question is the committee's: can this be controlled? Answer it.","Structure reads as control; defensiveness reads as loss of it."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-08","level":"senior","profession":"doctor","title":"The governing idea for a town hall","scenario":"Your all-staff town hall covers pay adjustments, a new parking system, the flu campaign, and the quality awards. Without a through-line, staff leave remembering none of it.","task":"Write one governing sentence that frames all four topics under a single theme, plus a one-line transition into each.","tips":["Find the theme that honestly connects them — 'investing in how you work' or similar.","The through-line is a promise the four topics keep.","Transitions should feel like chapters of one story, not four memos stapled together."],"focus":["structure","audience"]},
    {"id":"structure-doc-senior-09","level":"senior","profession":"doctor","title":"Recommendation, then support","scenario":"Your capital memo recommending the surgical robot buries the recommendation under pages of options analysis. The committee needs the pyramid: answer on top, support beneath.","task":"Write the top of the memo — recommendation first, then the three supporting pillars as headings.","tips":["Lead with the answer; the committee reads support to test it, not to find it.","Three pillars: clinical demand, financial return, competitive position — or your own.","Each pillar is a claim you can defend in one paragraph."],"focus":["structure","impact"],"placeholder":"Recommend approving the surgical robot purchase, for three reasons:"},
    {"id":"structure-doc-senior-10","level":"senior","profession":"doctor","title":"The chronology trap","scenario":"Your incident review for the board reads as a minute-by-minute timeline of a wrong-site procedure near-miss. The board doesn't need the clock; they need the pattern and the fix.","task":"Restructure the review into three sections: what happened, why it happened, what changes — a sentence each.","tips":["Timeline belongs in an appendix; findings belong up front.","'Why' means the system causes, not the clock times.","'What changes' is the only part the board can act on — make it concrete."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-11","level":"senior","profession":"doctor","title":"Two options, parallel structure","scenario":"You're presenting two paths for the aging cath lab: renovate in place or build new. Your draft describes them in different formats, so the committee can't compare them cleanly.","task":"Write both options in identical parallel structure — cost, timeline, disruption, upside — one line each.","tips":["Same categories, same order, for both options — comparison depends on it.","Parallel structure surfaces the real trade-off instead of hiding it.","End with your recommendation; parallel doesn't mean neutral."],"focus":["structure","precision"]},
    {"id":"structure-doc-senior-12","level":"senior","profession":"doctor","title":"The strategy on one page","scenario":"Your service-line strategy runs eight pages. The CEO wants the spine on one page for the board pre-read. You need a structure that survives compression.","task":"Write the one-page skeleton: one goal sentence, three strategic thrusts as headings, one supporting line under each.","tips":["The goal sentence is the destination; the thrusts are the routes.","Three thrusts, no more — the board holds three, not eight.","Each supporting line names the outcome, not the activity."],"focus":["structure","concision"]},
    {"id":"structure-doc-senior-13","level":"senior","profession":"doctor","title":"The Q&A prep grid","scenario":"Before a tense medical-staff meeting on the new documentation requirement, you want to structure your answers to the four questions you know are coming. Right now your notes are a wall of text.","task":"For the single hardest question, draft a PREP-structured answer of 4 sentences.","tips":["Point first, even when the point is uncomfortable.","One reason, one example — physicians respect specifics.","Restate the point; don't trail off into qualifications."],"focus":["structure","impact"]},
    {"id":"structure-doc-senior-14","level":"senior","profession":"doctor","title":"Grouping the complaint themes","scenario":"You have forty patient complaints from last quarter to summarize for the experience committee. Listed individually they overwhelm; the committee needs themes.","task":"Group the complaints into 3-4 themes and write each as a heading with a one-line summary and a count.","tips":["Themes should point at causes the hospital can change.","Attach a count to each so the committee can prioritize.","Order themes by frequency or by severity — say which."],"focus":["structure","precision"]},
    {"id":"structure-doc-senior-15","level":"senior","profession":"doctor","title":"SCQA to open a crisis brief","scenario":"You're briefing the executive team on a supply shortage of a critical IV medication. Your draft dives into procurement detail. It needs a four-part frame so the team grasps the shape before the specifics.","task":"Write the 4-sentence SCQA opening of the brief.","tips":["Situation: normal supply. Complication: the shortage and its cause.","The question the room is asking: how long, how bad, what now.","Answer it in one line, then the detail can follow."],"focus":["structure","clarity"],"placeholder":"We normally hold six weeks of this medication. As of today we have eleven days."},
    {"id":"structure-doc-senior-16","level":"senior","profession":"doctor","title":"The three-part close","scenario":"Your remarks to the retiring long-serving nurses wander because they have no shape. You want a structure: honor the past, mark the present, point to the future.","task":"Write a 4-5 sentence closing built on those three movements.","tips":["Three clear beats give even emotional remarks a spine.","One specific detail per beat beats general praise.","End on the future — that's what the room carries out the door."],"focus":["structure","audience"]},
    {"id":"structure-doc-senior-17","level":"senior","profession":"doctor","title":"The policy with no hierarchy","scenario":"The revised code-status policy is a flat run of twenty rules. Clinicians can't tell the load-bearing principles from the edge-case footnotes.","task":"Restructure it into a two-level hierarchy: 3-4 core principles, with the detailed rules nested under each.","tips":["Lead with principles a clinician can hold in their head at the bedside.","Nest the specifics; don't let them compete with the principles.","If a rule fits no principle, question whether it belongs."],"focus":["structure","clarity"]},
    {"id":"structure-doc-senior-18","level":"senior","profession":"doctor","title":"The board narrative arc","scenario":"Your annual report to the board is a data dump across every department. You want it to read as one arc: where we were, what we did, where we are, what's next.","task":"Write the four transition sentences that carry the report through those four stages.","tips":["Each stage is one sentence that hands off to the next.","The arc turns a data dump into a story the board can retell.","'What's next' should set up the year's ask, not just recap."],"focus":["structure","impact"]},
    {"id":"structure-doc-senior-19","level":"senior","profession":"doctor","title":"Pyramid for the regulator response","scenario":"A regulator cited three deficiencies. Your corrective-action response addresses them in a tangled order with overlapping fixes. It needs one plan of action structured by finding.","task":"Structure the response as: overall commitment, then one clearly headed section per finding.","tips":["Open with the single sentence of accountability the regulator wants to see.","One section per finding — root cause, fix, how you'll verify it holds.","Parallel structure across the three signals a systematic response."],"focus":["structure","precision"]},
    {"id":"structure-doc-senior-20","level":"senior","profession":"doctor","title":"The huddle script","scenario":"The daily operational huddle you lead has drifted into a shapeless status meeting. You want a fixed structure the whole team can follow in ten minutes.","task":"Write a four-item huddle structure with a one-line prompt for each segment.","tips":["Fixed segments make a short meeting reliable: safety, capacity, blockers, wins.","One prompt per segment keeps each contributor tight.","Order for action — put the thing that changes the day first."],"focus":["structure","concision"]},
    {"id":"structure-doc-senior-21","level":"senior","profession":"doctor","title":"The funding case, in three moves","scenario":"You're asking the foundation board to fund a mobile clinic. Your draft mixes need, plan, and impact in every paragraph. It needs three clean movements.","task":"Write the case as three headed sections — the need, the plan, the impact — one to two sentences each.","tips":["Need establishes the gap; plan shows the bridge; impact shows the far side.","Don't let the plan's detail crowd out the impact — donors buy impact.","Each section should stand alone if quoted."],"focus":["structure","impact"]},
    {"id":"structure-doc-senior-22","level":"senior","profession":"doctor","title":"The reorg, mapped","scenario":"You're announcing a service-line reorganization. Your draft describes new reporting lines in prose, and staff can't figure out where they land. It needs a structure that answers 'where am I' fast.","task":"Restructure the announcement so each affected group finds its own answer in a clearly headed block.","tips":["Structure by 'who you are', so each reader jumps to their block.","One block: your new leader, your new team, what changes for you.","A reorg's first job is to reduce anxiety — clear structure does that."],"focus":["structure","audience"]},
    {"id":"structure-doc-senior-23","level":"senior","profession":"doctor","title":"The five recommendations, ranked","scenario":"Your task force produced five recommendations for reducing ED boarding. Your report presents them as equals, but they differ hugely in cost and impact. Leadership needs a structure that guides sequencing.","task":"Restructure the five into a priority order with a one-line rationale for the ranking.","tips":["Rank by impact-per-effort, and say so.","Group into 'do now', 'plan for', 'consider later' if that clarifies.","A ranked list is a recommendation; an unranked list is homework for the reader."],"focus":["structure","precision"]},
    {"id":"structure-doc-senior-24","level":"senior","profession":"doctor","title":"SCQA for the merger update","scenario":"You're updating staff on integration progress after the affiliation with the regional network. Your draft lists activities. Staff want the shape: where things stood, what's changed, what they're wondering, the answer.","task":"Write a 4-sentence SCQA staff update.","tips":["Situation: the affiliation as announced. Complication: the real integration work.","The question is the staff's: is this still on track and does it affect me?","Answer plainly — vague updates breed rumor."],"focus":["structure","audience"]},
    {"id":"structure-doc-senior-25","level":"senior","profession":"doctor","title":"The one-pager that carries the year","scenario":"The CEO wants a single structured page summarizing the department's year to brief the board chair. You have abundant material and no shape. The structure has to do the work.","task":"Write the one-pager skeleton: a headline, three section titles, and the one sentence that opens each section.","tips":["The headline is the year's story in a line.","Three sections, chosen so together they answer 'how did the department do'.","Each opening sentence is the section's conclusion, not its warm-up."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-doc-senior-01","level":"senior","profession":"doctor","title":"The padded board summary","scenario":"Your executive summary for the board opens: 'It is important to note that, at this point in time, we are in the process of undertaking a comprehensive review of our current staffing situation.' Under the padding is one fact: staffing is being reviewed.","task":"Rewrite that sentence in the fewest words that keep the meaning.","tips":["Delete 'it is important to note that' — if it weren't, you'd cut it.","'At this point in time' is 'now'; 'in the process of undertaking' is 'are'.","Say the fact; trust the reader to weigh it."],"focus":["concision","clarity"],"placeholder":"We're reviewing staffing."},
    {"id":"concise-doc-senior-02","level":"senior","profession":"doctor","title":"Halve the crisis memo","scenario":"Your all-staff memo about the water-main break and its effect on the OR schedule runs eight sentences of throat-clearing before the two that matter. Staff need it in a glance.","task":"Cut the memo to its two load-bearing sentences.","tips":["Find the two sentences a nurse would act on and delete the rest.","Context that everyone already knows is wasted words in a crisis.","One instruction, one contact — that's often the whole memo."],"focus":["concision","impact"]},
    {"id":"concise-doc-senior-03","level":"senior","profession":"doctor","title":"The nominalization pile-up","scenario":"Your policy draft reads: 'The implementation of the utilization of the new protocol will result in the reduction of variation.' Buried verbs are hiding as nouns.","task":"Rewrite the sentence with live verbs and no nominalizations.","tips":["'The implementation of' becomes 'implementing' — or just 'the protocol'.","Turn noun-strings back into verbs: 'reduce variation', not 'result in the reduction of'.","Live verbs are shorter and clearer at once."],"focus":["concision","precision"],"placeholder":"The new protocol will reduce variation."},
    {"id":"concise-doc-senior-04","level":"senior","profession":"doctor","title":"Cut the hedge stack","scenario":"Your recommendation to the CEO reads: 'We would perhaps tentatively suggest that it might possibly be advisable to consider expanding hours.' Five hedges smother one recommendation.","task":"Rewrite it as a single clear recommendation, keeping at most one honest qualifier.","tips":["Stacked hedges read as no conviction, not as caution.","Keep the one qualifier that's true; delete the four that are reflex.","'We recommend expanding hours' can carry a caveat without four of them."],"focus":["concision","impact"],"placeholder":"We recommend expanding weekend hours."},
    {"id":"concise-doc-senior-05","level":"senior","profession":"doctor","title":"The redundant pairs","scenario":"Your quality report is thick with doublets: 'each and every,' 'first and foremost,' 'full and complete,' 'plans and preparations.' They add length, not meaning.","task":"Rewrite a 3-sentence excerpt (you supply it) stripping every redundant pair to one word.","tips":["Redundant pairs are habit, not emphasis — pick the stronger word.","'Full and complete' is just 'complete'.","Read it aloud; the pairs slow the sentence without adding to it."],"focus":["concision","precision"]},
    {"id":"concise-doc-senior-06","level":"senior","profession":"doctor","title":"The meta-commentary trap","scenario":"Your board note keeps narrating itself: 'In this section I will explain... As mentioned above... It should be noted that... Before I conclude, let me summarize.' The scaffolding outweighs the content.","task":"Rewrite a short passage deleting all the self-narration and keeping only the substance.","tips":["Readers don't need you to announce what you're about to say — just say it.","'As mentioned above' means you're repeating yourself; cut one instance.","The best structure is invisible; you don't have to describe it."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-07","level":"senior","profession":"doctor","title":"The email that could be a line","scenario":"You've written four paragraphs to the CFO to say the department will hit its Q3 target. It's good news that needs one sentence, not a page.","task":"Reduce the whole email to a single sentence plus, if needed, one line of context.","tips":["Good news rarely needs a paragraph — it needs a sentence.","If you're padding, ask what you're afraid to just say.","Offer detail on request rather than pre-loading it."],"focus":["concision","clarity"],"placeholder":"We'll hit the Q3 target — final numbers Friday."},
    {"id":"concise-doc-senior-08","level":"senior","profession":"doctor","title":"The bloated policy preamble","scenario":"The new hand-hygiene policy opens with three paragraphs on the history of infection control before it states the one behavior it wants. Clinicians never reach the ask.","task":"Cut the preamble and write the policy's core requirement in two sentences.","tips":["A policy's job is to say what to do — lead with that.","History convinces no one at the sink; the requirement does.","If the rationale matters, one sentence of it will do."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-09","level":"senior","profession":"doctor","title":"The over-qualified 'no'","scenario":"You're declining a department's request for a new position. Your draft wraps the no in nine sentences of cushioning so thick the reader isn't sure they were declined.","task":"Write a clear, kind decline in three sentences — no padding.","tips":["Clear is kind: an unclear no forces them to ask again.","One sentence of reason, one of what could change it — that's the cushion.","Cushioning past a point becomes cruelty dressed as courtesy."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-10","level":"senior","profession":"doctor","title":"The filler-word audit","scenario":"Your talking points for the medical staff meeting are riddled with 'basically,' 'actually,' 'in order to,' 'the fact that,' 'in terms of.' Spoken aloud, they blur the message.","task":"Rewrite a 3-sentence excerpt removing every filler and tightening what remains.","tips":["'In order to' is 'to'; 'the fact that' is usually deletable entirely.","'Basically' and 'actually' rarely earn their place — cut on sight.","'In terms of' hides a vaguer thought; find the real preposition."],"focus":["concision","precision"]},
    {"id":"concise-doc-senior-11","level":"senior","profession":"doctor","title":"The three-page memo, in a paragraph","scenario":"You wrote three pages recommending the ICU staffing model change. The CEO reads memos on her phone between meetings and asked for the short version. The full memo can be the appendix.","task":"Write the one-paragraph version: recommendation, key reason, cost, next step.","tips":["Four sentences can carry a three-page memo if each earns its place.","The reader can request the pages; give them the decision first.","Cost and next step are what turns a memo into a decision."],"focus":["concision","impact"]},
    {"id":"concise-doc-senior-12","level":"senior","profession":"doctor","title":"The circular sentence","scenario":"Your report contains: 'The reason for the delay is due to the fact that the vendor was late.' The sentence says 'late because late' with extra words.","task":"Rewrite it in the fewest words.","tips":["'The reason for X is due to the fact that' collapses to 'X because'.","Watch for sentences that restate their subject as their predicate.","Six words can replace sixteen here."],"focus":["concision","clarity"],"placeholder":"The vendor was late."},
    {"id":"concise-doc-senior-13","level":"senior","profession":"doctor","title":"The over-explained instruction","scenario":"Your downtime instruction to nurses runs a full paragraph explaining why the backup process exists before telling them what to do. In a crisis they need the action, not the history.","task":"Cut it to the two action sentences a nurse needs mid-crisis.","tips":["In an emergency, action beats explanation every time.","One sentence: what to do. One sentence: who to call.","The 'why' can live in the training, not the crisis card."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-14","level":"senior","profession":"doctor","title":"The adjective glut","scenario":"Your foundation letter describes 'the incredibly important, absolutely vital, truly transformational new pediatric wing.' The adjectives compete and cancel; the reader tunes out.","task":"Rewrite the phrase with one precise word doing the work, plus the fact that proves it.","tips":["Piled intensifiers signal weakness, not strength.","One concrete fact persuades more than four adjectives.","Let the number carry the weight the adjectives were straining to."],"focus":["concision","precision"]},
    {"id":"concise-doc-senior-15","level":"senior","profession":"doctor","title":"The slide with eight bullets","scenario":"Your board slide on ED throughput has eight bullets, three of them sub-points of another. The board can't find the message in the density.","task":"Cut the slide to three bullets that carry the whole point.","tips":["A board slide is a headline, not a document — three bullets max.","Merge sub-points into their parent or drop them.","If a bullet doesn't change the board's thinking, it's noise."],"focus":["concision","structure"]},
    {"id":"concise-doc-senior-16","level":"senior","profession":"doctor","title":"The apology that won't stop","scenario":"Your service-recovery note to a family who waited hours apologizes six times in five sentences. The repetition dilutes the sincerity and buries the concrete remedy.","task":"Rewrite it: one clear apology, the remedy, and a contact — three sentences.","tips":["Apologize once, meaningfully; six times reads as anxious, not sorry.","The remedy matters more than the third apology.","End with a person's name and number, not another 'sorry'."],"focus":["concision","impact"]},
    {"id":"concise-doc-senior-17","level":"senior","profession":"doctor","title":"The passive detour","scenario":"Your incident note reads: 'It was determined by the review team that errors had been made in the process by which orders were verified.' Passive voice tripled the length and hid the actor.","task":"Rewrite it in active voice, as short as it goes.","tips":["Name who did what — passive voice is often longer and vaguer.","'It was determined by the review team' is 'the review found'.","Active voice takes accountability and saves words at once."],"focus":["concision","clarity"],"placeholder":"The review found that order verification failed."},
    {"id":"concise-doc-senior-18","level":"senior","profession":"doctor","title":"The recap nobody needs","scenario":"Your follow-up email to the executive team spends the first half recapping the meeting everyone just attended. The action items — the point — start halfway down.","task":"Cut the recap entirely and write the email as just the action items with owners.","tips":["People who were in the room don't need the room narrated back.","Lead with the decisions and who owns each.","A follow-up email is a to-do list, not minutes."],"focus":["concision","structure"]},
    {"id":"concise-doc-senior-19","level":"senior","profession":"doctor","title":"The over-caveated forecast","scenario":"Your capacity forecast to the COO is so laden with 'assuming,' 'subject to,' 'pending,' and 'all else equal' that the actual projection is unreadable. She needs a number and one real caveat.","task":"Rewrite the forecast: the projection, then the single caveat that could actually move it.","tips":["Most caveats are reflexes; keep the one that's material.","State the number confidently, then name its biggest risk.","A forecast smothered in caveats gives no basis for a decision."],"focus":["concision","precision"]},
    {"id":"concise-doc-senior-20","level":"senior","profession":"doctor","title":"The bloated thank-you","scenario":"Your note thanking the nursing team after the mass-casualty drill runs three paragraphs of general praise. One specific, brief thank-you would land harder.","task":"Rewrite it as three tight sentences: what they did, why it mattered, thanks.","tips":["Specific beats effusive — name the actual thing they did well.","General praise is forgettable; a concrete detail sticks.","Brevity signals you noticed the real thing, not just that you owed a note."],"focus":["concision","impact"]},
    {"id":"concise-doc-senior-21","level":"senior","profession":"doctor","title":"The requirement buried in prose","scenario":"Your protocol update contains a mandatory step in the middle of a long descriptive paragraph, where clinicians miss it. It needs to be extracted and stated plainly.","task":"Pull the requirement out and state it as one imperative sentence, cutting the surrounding prose.","tips":["Requirements should never hide inside description.","One imperative sentence: do this, when.","If it's mandatory, it deserves to stand alone."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-22","level":"senior","profession":"doctor","title":"The wordy transition","scenario":"Your strategy document is stitched with 'having said that,' 'with that being said,' 'moving forward,' 'at the end of the day.' The connective tissue is all filler.","task":"Rewrite a 3-sentence passage replacing every filler transition with a real one or none.","tips":["'At the end of the day' means nothing; cut it.","A good transition names the logical turn — 'but', 'so', 'because'.","Often the cleanest transition is a period and a new sentence."],"focus":["concision","clarity"]},
    {"id":"concise-doc-senior-23","level":"senior","profession":"doctor","title":"The over-built ask","scenario":"You need the CFO to approve $80K for a locum. Your email builds toward the ask through five paragraphs of justification, so the number appears in paragraph six.","task":"Rewrite it: the ask and number first, then the two-sentence justification.","tips":["Lead with the ask; justification is support, not runway.","Two sentences of reason usually suffice for a clear ask.","Trust the CFO to ask for more if she needs it."],"focus":["concision","impact"],"placeholder":"I'm requesting $80K in locum funding to cover the January gap."},
    {"id":"concise-doc-senior-24","level":"senior","profession":"doctor","title":"The repeated point","scenario":"Your memo makes the same argument — that consolidating labs saves money — in three different paragraphs with different words. The repetition weakens rather than reinforces.","task":"Consolidate the three into one sharp statement of the argument.","tips":["Saying it three ways signals you don't trust it said once.","Pick the sharpest version and cut the other two.","One well-made point outweighs three restatements."],"focus":["concision","precision"]},
    {"id":"concise-doc-senior-25","level":"senior","profession":"doctor","title":"The final polish","scenario":"Your board resolution is clear but 40% longer than it needs to be — every sentence carries a spare clause or two. This is the last pass before it goes out.","task":"Take a 4-sentence excerpt (you supply it) and cut it by a third without losing meaning.","tips":["The last third is usually the easiest to cut — it's mostly reinforcement.","Cut clauses that qualify things no one is questioning.","Read the cut version aloud; if nothing's missing, ship it."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-doc-senior-01","level":"senior","profession":"doctor","title":"'Significantly' is not a number","scenario":"Your board update says ED wait times 'improved significantly' and readmissions dropped 'considerably.' The board can't act on adjectives; a skeptical director will ask what the numbers are.","task":"Rewrite the sentence replacing both vague intensifiers with specific figures and a baseline.","tips":["'Significantly' hides a number — supply it and a comparison point.","Always pair a figure with what it's measured against.","Numbers survive the skeptic's follow-up; adjectives don't."],"focus":["precision","impact"],"placeholder":"ED wait times fell from 41 to 27 minutes; 30-day readmissions dropped 2.1 points."},
    {"id":"precision-doc-senior-02","level":"senior","profession":"doctor","title":"Data to one insight","scenario":"You have a table of twelve months of OR utilization numbers to present to the surgical committee. Reading the table aloud will lose the room. There's one insight in it: afternoon blocks are chronically under-booked.","task":"Write the one-sentence insight the table supports, with the number that proves it.","tips":["A table's job is to support one takeaway — say the takeaway.","Cite the single number that carries the insight, not all twelve.","If you can't name the insight, you're not ready to present the table."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-03","level":"senior","profession":"doctor","title":"What, so what, now what","scenario":"You're reporting a rise in central-line infections to the quality committee. Your draft states the number and stops. The committee needs to know what it means and what you're doing.","task":"Write three sentences: the fact, its significance, the action you're taking.","tips":["'What' is the data; 'so what' is why it matters; 'now what' is the move.","A number without a 'so what' leaves the committee to guess.","End with the action — that's what turns a report into leadership."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-04","level":"senior","profession":"doctor","title":"The skeptic's test","scenario":"You're claiming to the finance committee that the new scheduling system 'will pay for itself in a year.' A skeptical CFO will ask how you know. Your draft offers no basis.","task":"Rewrite the claim so it survives the skeptic — with the assumption and the number behind it.","tips":["Every claim of savings needs a mechanism and a number.","State the assumption openly — hidden assumptions get exposed in the room.","'Pays for itself' means nothing until you show the math."],"focus":["precision","impact"],"placeholder":"The system costs $120K and cuts scheduling labor by roughly $140K a year, based on current overtime."},
    {"id":"precision-doc-senior-05","level":"senior","profession":"doctor","title":"'Soon' and 'a lot'","scenario":"Your message to the COO says the flex unit will open 'soon' and will help 'a lot' with boarding. Neither word lets her plan. She needs a date and a magnitude.","task":"Rewrite the sentence with a specific date and a quantified effect.","tips":["'Soon' is a date you haven't committed to — commit.","'A lot' is a number you haven't estimated — estimate it, with a range if needed.","Vague words feel safe but leave the reader unable to act."],"focus":["precision","clarity"],"placeholder":"The flex unit opens March 10 and adds 12 beds, cutting boarding by roughly a third."},
    {"id":"precision-doc-senior-06","level":"senior","profession":"doctor","title":"The unsourced claim","scenario":"Your policy rationale states 'studies show' that the new protocol reduces harm, with no study named. The medical staff will not accept 'studies show' from their own leader.","task":"Rewrite the claim to name the evidence specifically, or to state honestly what evidence you have.","tips":["'Studies show' with no citation invites dismissal.","Name the source, or say plainly 'in our own data' or 'in three trials'.","If the evidence is thin, say so — physicians respect calibrated honesty."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-07","level":"senior","profession":"doctor","title":"The trend without a baseline","scenario":"Your report says patient falls are 'trending up.' Up from what, over what period? The safety committee can't judge severity without the baseline and the timeframe.","task":"Rewrite it with the baseline, the current figure, and the period.","tips":["A trend needs two points and a clock to mean anything.","'Up' from three to four is not 'up' from three to thirty.","Give the rate, not just the count, if volume changed too."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-08","level":"senior","profession":"doctor","title":"The budget number that floats","scenario":"Your variance note says the department is 'over budget' without saying by how much or on what. The CFO needs the figure and the driver, not the fact of variance.","task":"Rewrite it with the exact overage, the category, and the cause in one sentence.","tips":["'Over budget' is a category, not a number — give the number.","Attach it to a line item and a cause.","Precision here signals you're on top of it, not surprised by it."],"focus":["precision","impact"],"placeholder":"We're $410K over on agency nursing, driven by four unfilled ICU positions."},
    {"id":"precision-doc-senior-09","level":"senior","profession":"doctor","title":"The chart junk","scenario":"Your board slide shows six trend lines, two axes, and a legend of eight items. The one thing that matters — the safety metric crossing target — is lost in the clutter.","task":"Describe in two sentences what the stripped-down chart should show, and the single point it should make.","tips":["A board chart makes one point — design everything to serve it.","Cut lines that don't support the takeaway.","Say the takeaway in the title, so the chart confirms rather than teaches."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-10","level":"senior","profession":"doctor","title":"The percentage without the denominator","scenario":"Your report celebrates that 'compliance rose 50%.' From 2% to 3% is a 50% rise and nearly meaningless. Whoever reads it needs the absolute numbers.","task":"Rewrite the claim giving both the percentage and the absolute figures.","tips":["A percentage change without a base can mislead badly.","Pair every rate with the counts behind it.","If the base is tiny, the honest framing says so."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-11","level":"senior","profession":"doctor","title":"The 'we expect' with no basis","scenario":"Your capacity brief says 'we expect flu season to strain the ICU.' On what basis, and how much? The executive team needs the projection grounded in something.","task":"Rewrite it with the basis for the expectation and a quantified projection.","tips":["'We expect' should be followed by 'because' and a number.","Ground the projection in last year's data or current trajectory.","A grounded projection can be planned against; a hunch can't."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-12","level":"senior","profession":"doctor","title":"The outcome claim, evidenced","scenario":"You're telling the foundation the donated equipment 'made a real difference.' Donors want the specific difference, in numbers they can picture. Your draft has only the adjective.","task":"Rewrite the claim with one concrete, quantified outcome.","tips":["'A real difference' is a placeholder for a number you have.","One vivid, specific figure beats a paragraph of gratitude.","Tie the number to the gift so the causal line is clear."],"focus":["precision","impact"],"placeholder":"The two donated ventilators let us keep 34 critically ill patients here instead of transferring them."},
    {"id":"precision-doc-senior-13","level":"senior","profession":"doctor","title":"The vague timeline","scenario":"Your integration update tells staff the merger work is 'progressing well' and will be 'done before too long.' Staff read that as evasion. They need concrete milestones and dates.","task":"Rewrite it with two dated milestones and the current status of each.","tips":["'Progressing well' with no dates breeds distrust.","Name the next two milestones and when they land.","Concrete dates, even if some slip, beat reassuring fog."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-14","level":"senior","profession":"doctor","title":"The comparison that isn't","scenario":"Your quality report says the hospital performs 'better than average' on infections. Better than whose average, by how much? A board member will want the peer set and the gap.","task":"Rewrite the claim naming the benchmark and the size of the difference.","tips":["'Better than average' needs a named comparison group.","Give the gap, not just the direction.","Precision protects you when someone checks the benchmark."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-15","level":"senior","profession":"doctor","title":"The risk stated without probability","scenario":"Your enterprise-risk note lists 'cyberattack' as a threat with no sense of likelihood or impact magnitude. The board can't prioritize a risk with no dimensions.","task":"Rewrite the entry with a rough likelihood and a quantified potential impact.","tips":["A risk without likelihood and impact can't be ranked.","Even a rough band — high/medium, dollars, days down — beats nothing.","Say the basis for the estimate so it isn't just a feeling."],"focus":["precision","structure"]},
    {"id":"precision-doc-senior-16","level":"senior","profession":"doctor","title":"The staffing gap, quantified","scenario":"Your case to the CEO says the unit is 'short-staffed and stretched thin.' She's heard that from every department. You need the specific shortfall and its measurable effect.","task":"Rewrite it with the exact vacancy count and one metric it's moving.","tips":["Every leader claims 'stretched thin' — the number sets you apart.","Tie the vacancy to a measured outcome: overtime, delays, a safety metric.","Specifics turn a complaint into a fundable case."],"focus":["precision","impact"],"placeholder":"We're down 4 of 22 nurses, driving overtime to 18% and delaying 1 in 5 discharges."},
    {"id":"precision-doc-senior-17","level":"senior","profession":"doctor","title":"So-what for the survey result","scenario":"You're reporting that patient-experience scores rose three points. The committee's unspoken question is 'so what?' Your draft states the rise and stops.","task":"Write two sentences: the result, then what it means for the hospital concretely.","tips":["A number without an interpretation makes the reader do your job.","Translate the points into something real — reputation, volume, ranking.","The 'so what' is where your judgment shows."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-18","level":"senior","profession":"doctor","title":"The estimate dressed as fact","scenario":"Your capital proposal states the renovation 'will cost $2.4M' when that figure is a rough early estimate with a wide range. Presenting an estimate as a fact will burn you when it moves.","task":"Rewrite the figure so its uncertainty is honest and useful.","tips":["State a range when you have one — false precision destroys trust later.","Name the stage: 'early estimate,' 'firm quote,' 'ceiling.'","Honest uncertainty is more credible than a confident wrong number."],"focus":["precision","clarity"],"placeholder":"Early estimates put the renovation at $2.2–2.6M; we'll have firm quotes by March."},
    {"id":"precision-doc-senior-19","level":"senior","profession":"doctor","title":"The evidence for the 'no'","scenario":"You're denying a physician's request for a costly new device on the grounds that 'the evidence isn't there.' He'll ask what evidence you reviewed. Your draft is bare assertion.","task":"Rewrite the denial citing the specific basis for the decision.","tips":["'The evidence isn't there' invites 'which evidence did you look at?'","Name what you reviewed and what threshold it missed.","A sourced 'no' is respected; an asserted one is fought."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-20","level":"senior","profession":"doctor","title":"The throughput claim","scenario":"You're telling the board the new patient-flow model 'freed up capacity.' By how much, measured how? Without the figure, the board can't judge whether to expand it.","task":"Rewrite the claim with the capacity gained and how it's measured.","tips":["'Freed up capacity' is a result you can count — count it.","Name the unit: beds, hours, discharges by noon.","A measurable claim lets the board fund more of it."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-21","level":"senior","profession":"doctor","title":"The regulator-facing precision","scenario":"You're responding to a regulator's finding. Your draft says the hospital 'took steps to address' the issue. A regulator needs the specific actions, dates, and verification, not 'took steps.'","task":"Rewrite the sentence with the concrete action, the date it was completed, and how compliance is verified.","tips":["Regulators discount vague remediation language — be specific.","Action, date, verification method: all three.","Precision here is the difference between closed and reopened findings."],"focus":["precision","clarity"]},
    {"id":"precision-doc-senior-22","level":"senior","profession":"doctor","title":"The 'many' patients","scenario":"Your case for a new clinic says 'many patients' face long travel times. Many is a word that hides whether it's dozens or thousands. The board needs the count and the distance.","task":"Rewrite it with the number of patients and the specific travel burden.","tips":["'Many' is a number you're choosing not to give — give it.","Pair the count with the concrete burden: miles, minutes, missed appointments.","A quantified need is a fundable need."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-23","level":"senior","profession":"doctor","title":"The insight, not the dashboard","scenario":"You've pasted the full operations dashboard into your executive email — fifteen metrics. The COO doesn't want the dashboard; she wants the one thing that changed and needs a decision.","task":"Write the one-sentence insight from the dashboard plus the decision it prompts.","tips":["A dashboard is raw material; the insight is the product.","Name the single metric that moved and why it matters this week.","End with the decision the insight forces."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-24","level":"senior","profession":"doctor","title":"The confidence calibration","scenario":"You're forecasting next quarter's surgical volume for the finance committee. Your draft presents a single number as if it were certain, when your confidence is genuinely moderate.","task":"Rewrite the forecast to convey both the estimate and your honest confidence in it.","tips":["State the number and the range that reflects your real uncertainty.","Name what would push it high or low.","Calibrated confidence is a leadership signal, not a weakness."],"focus":["precision","impact"]},
    {"id":"precision-doc-senior-25","level":"senior","profession":"doctor","title":"The claim that needs a source","scenario":"Your press-ready statement says the hospital is 'the region's leading center' for stroke care. If a reporter asks 'by what measure,' you need a defensible, specific answer, not a slogan.","task":"Rewrite the claim so it's specific, sourced, and survives a reporter's challenge.","tips":["Superlatives invite 'says who?' — be ready with the measure.","Name the metric and the source: volume, outcomes, a certification.","A precise claim protects the hospital; a slogan exposes it."],"focus":["precision","clarity"],"placeholder":"We're the region's only certified comprehensive stroke center, treating 900 cases a year."}
  ],
  "executive-presence": [
    {"id":"presence-doc-senior-01","level":"senior","profession":"doctor","title":"Own the recommendation","scenario":"You've laid out three options for the maternity-unit staffing model to the board and stopped, leaving them to choose. The board looks to you as the expert and finds a neutral menu instead of a recommendation.","task":"Rewrite the close so it names your recommendation and why, after presenting the options.","tips":["Presenting options is analysis; recommending one is leadership.","The board wants your judgment — that's what they appointed you for.","State the pick and the single reason that decides it."],"focus":["impact","clarity"],"placeholder":"Of the three, I recommend option B —"},
    {"id":"presence-doc-senior-02","level":"senior","profession":"doctor","title":"Fact versus judgment","scenario":"Your board memo blends verified facts with your interpretation so seamlessly the board can't tell which is which. When they push, you want to show clearly what's known versus what you conclude.","task":"Rewrite a 3-sentence passage that separates the facts from your judgment explicitly.","tips":["Signal the seam: 'The data shows X. In my judgment, that means Y.'","Facts you defend with evidence; judgment you defend with reasoning.","Mixing them undermines both; separating them strengthens both."],"focus":["impact","precision"]},
    {"id":"presence-doc-senior-03","level":"senior","profession":"doctor","title":"Signpost the structure","scenario":"You're about to give a five-minute update to the executive team on winter readiness. You tend to launch straight in, and listeners lose the thread. You want to signpost where you're going.","task":"Write the two-sentence opening that tells the room the structure before you deliver it.","tips":["Telling the room your three points first lets them follow all three.","Signposting reads as command, not as filler.","'I'll cover capacity, staffing, and supply — starting with capacity.'"],"focus":["structure","impact"]},
    {"id":"presence-doc-senior-04","level":"senior","profession":"doctor","title":"The hedge that undercuts authority","scenario":"You open your board recommendation with 'I'm not really the expert here, but...' about a matter squarely in your remit. The disclaimer hands away the authority the board needs you to hold.","task":"Rewrite the opening to state your recommendation with earned confidence.","tips":["False modesty in your own domain reads as abdication.","You can be open to challenge without disowning your expertise.","Lead with the recommendation; invite debate after, not before."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-05","level":"senior","profession":"doctor","title":"The calm crisis voice","scenario":"You're addressing the medical staff during an active capacity crisis. Your draft is anxious and scattered, mirroring the room. The staff need to hear steadiness and a clear next move from their leader.","task":"Write a 3-4 sentence opening that projects calm, names the situation plainly, and gives one clear directive.","tips":["Your tone sets the room's — steadiness is a decision.","Name the hard reality without drama, then give the action.","Short, plain sentences read as control under pressure."],"focus":["impact","audience"]},
    {"id":"presence-doc-senior-06","level":"senior","profession":"doctor","title":"From menu to stance","scenario":"Your written brief on whether to pursue the trauma-center designation lists pros and cons in balance and takes no position. The CEO wrote back: 'What do you actually think?'","task":"Write a 3-sentence answer that takes a clear position and defends it.","tips":["'What do you think' is a request to stop balancing and decide.","State your position in the first sentence.","Give the reason that outweighs the cons you listed."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-07","level":"senior","profession":"doctor","title":"The apology that overcorrects","scenario":"After a scheduling error affected your division, your all-staff note is so self-flagellating it makes people worry you've lost your footing. Presence means owning it cleanly and moving to the fix.","task":"Rewrite it: brief ownership, then the corrective action, in a steady voice.","tips":["Own it once, plainly — over-apologizing signals instability.","Pivot fast to what you're doing about it.","Accountability with composure is the presence you want."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-08","level":"senior","profession":"doctor","title":"The recommendation with a spine","scenario":"You're advising the board against acquiring the failing outpatient group everyone else is excited about. It's an unpopular call. Presence means stating it clearly and standing behind the reasoning.","task":"Write a 3-4 sentence recommendation that takes the unpopular position with conviction.","tips":["Unpopular calls need more clarity, not more hedging.","State the recommendation, then the risk others are underweighting.","Conviction plus sound reasoning is how a minority view earns a hearing."],"focus":["impact","structure"]},
    {"id":"presence-doc-senior-09","level":"senior","profession":"doctor","title":"Judgment on the record","scenario":"The board asks for your read on whether the quality program is working. The honest answer is 'yes on process, not yet on outcomes.' You want to deliver that nuanced judgment without sounding wishy-washy.","task":"Write a 3-sentence answer that gives a clear, nuanced judgment.","tips":["Nuance isn't hedging if it's stated with structure.","Separate the two verdicts cleanly: process yes, outcomes not yet.","A precise mixed verdict shows command; a vague one shows avoidance."],"focus":["impact","precision"]},
    {"id":"presence-doc-senior-10","level":"senior","profession":"doctor","title":"The room-reading open","scenario":"You're opening a tense medical-staff meeting where physicians are angry about the new EHR. Pretending the tension isn't there costs you credibility. Presence means naming it and holding the room.","task":"Write a 2-3 sentence opening that acknowledges the frustration and asserts a way forward.","tips":["Name the elephant — it disarms more than ignoring it.","Acknowledge without groveling; you're still leading the meeting.","Pivot to the structure: here's how we'll use this hour."],"focus":["impact","audience"]},
    {"id":"presence-doc-senior-11","level":"senior","profession":"doctor","title":"The confident 'I don't know'","scenario":"At the board meeting a director asks a question you can't answer with certainty. You want to say so without losing authority — the opposite of bluffing.","task":"Write a 2-3 sentence response that admits the gap and commits to a specific follow-up.","tips":["A confident 'I don't know, and here's how I'll find out' builds trust.","Never bluff a board — one exposed bluff costs all your credibility.","Name when you'll have the answer."],"focus":["impact","clarity"],"placeholder":"I don't have that figure in front of me. I'll have it to you by Thursday —"},
    {"id":"presence-doc-senior-12","level":"senior","profession":"doctor","title":"The stance in one line","scenario":"The CEO stops you in the hall: 'Should we bid on the county contract or not?' You have thirty seconds and a considered view. Presence is delivering it crisply, not deferring to a longer memo.","task":"Write a 2-sentence verbal answer that gives your position and the deciding factor.","tips":["A hallway answer is a test of whether you actually have a view.","Lead with yes or no, then the one factor that decides it.","Offer the memo after the answer, not instead of it."],"focus":["impact","concision"]},
    {"id":"presence-doc-senior-13","level":"senior","profession":"doctor","title":"Separating the emotion from the call","scenario":"A beloved program is losing money and must probably close. Your draft to the executive team is colored by your own regret, blurring the recommendation. Presence means acknowledging the loss but making the call cleanly.","task":"Write a 3-4 sentence recommendation that honors the loss and still delivers a clear decision.","tips":["Name the human cost honestly, then make the call it can't change.","Don't let regret soften the recommendation into mush.","Feeling and judgment can coexist if you keep them in separate sentences."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-14","level":"senior","profession":"doctor","title":"The board question, owned","scenario":"A board member challenges your capital request as too aggressive. Your instinct is to retreat and trim the ask on the spot. Presence is holding your reasoning while genuinely engaging the challenge.","task":"Write a 3-sentence response that engages the challenge without caving.","tips":["Engaging a challenge isn't the same as surrendering to it.","Restate the reasoning behind the number, then invite the specific concern.","Caving instantly signals the number was never defensible."],"focus":["impact","audience"]},
    {"id":"presence-doc-senior-15","level":"senior","profession":"doctor","title":"The vision, stated plainly","scenario":"You're opening the department's annual retreat. Your draft is a list of operational goals with no unifying vision, so it lands flat. Presence means articulating where you're leading them.","task":"Write a 3-sentence opening that states a clear direction for the year in your own voice.","tips":["A leader names the destination, not just the tasks.","Say the one thing you want to be true a year from now.","Vision in plain words beats vision in buzzwords."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-16","level":"senior","profession":"doctor","title":"The steady bad-news delivery","scenario":"You must tell the executive team that the quality metric they've championed has regressed. Your draft either buries it or panics. Presence is delivering it flatly and moving to what you'll do.","task":"Write a 3-sentence delivery: the regression, the likely cause, the corrective step.","tips":["Deliver bad news in the same steady voice you'd deliver good.","Panic and burial both cost trust; plain statement builds it.","Follow the fact immediately with the response."],"focus":["impact","structure"]},
    {"id":"presence-doc-senior-17","level":"senior","profession":"doctor","title":"The recommendation under scrutiny","scenario":"The finance committee is skeptical of your proposed service-line investment. You've been circling with qualifications. They need you to plant a flag: recommend it or don't.","task":"Write a 3-sentence close that plants the flag and gives the committee a reason to trust it.","tips":["Circling reads as uncertainty; a planted flag reads as leadership.","Recommend, then give the strongest single reason.","Acknowledge the risk in one clause — but don't let it move the flag."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-18","level":"senior","profession":"doctor","title":"The composed correction","scenario":"In a leadership meeting, a colleague misstates your department's data in a way that could mislead a decision. You need to correct it firmly but without ego, keeping your standing and the relationship.","task":"Write a 2-3 sentence correction that sets the record straight and stays collegial.","tips":["Correct the fact, not the person.","Lead with the accurate number, calmly stated.","Firm and gracious beats either meek or combative."],"focus":["impact","precision"]},
    {"id":"presence-doc-senior-19","level":"senior","profession":"doctor","title":"The signposted board presentation","scenario":"Your ten-minute board presentation on the strategic plan has no roadmap, so the board can't track where you are. Presence includes making your structure visible as you go.","task":"Write the opening and the three transition lines that signpost the presentation's structure.","tips":["Tell them the map, then narrate the turns as you take them.","'That covers where we are; now, where we're going.'","Visible structure lets the board follow and lets you look in command."],"focus":["structure","impact"]},
    {"id":"presence-doc-senior-20","level":"senior","profession":"doctor","title":"The 'this is my call' moment","scenario":"After consulting widely, you've decided to standardize the sepsis protocol over some objections. Your draft distributes the decision vaguely among 'the committee.' Presence means owning that it's your call.","task":"Write a 2-3 sentence statement that owns the decision as yours while crediting the input.","tips":["Consultation informs the decision; it doesn't dilute ownership.","'I've decided, having heard the committee' owns it cleanly.","Hiding behind the group weakens the decision and you."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-21","level":"senior","profession":"doctor","title":"The measured optimism","scenario":"You're closing a rough quarter's staff update. Your draft is either grimly bleak or falsely upbeat. Presence is honest acknowledgment of the difficulty plus grounded confidence in the path.","task":"Write a 3-sentence close that's honest about the hard quarter and credibly hopeful.","tips":["Earned optimism names the difficulty first.","Ground the hope in a specific thing that's improving.","False cheer erodes trust; grounded confidence builds it."],"focus":["impact","audience"]},
    {"id":"presence-doc-senior-22","level":"senior","profession":"doctor","title":"The clear ask of the board","scenario":"You need the board to approve a policy change, but your presentation trails off without a clear request, so the meeting moves on and nothing is decided. Presence is asking plainly for the decision.","task":"Write the 2-sentence closing ask that puts the decision squarely before the board.","tips":["End with the specific thing you need them to approve.","A presentation without an ask is information, not leadership.","Name the vote you're requesting, so the chair can call it."],"focus":["impact","clarity"],"placeholder":"I'm asking the board to approve the revised code-status policy today."},
    {"id":"presence-doc-senior-23","level":"senior","profession":"doctor","title":"The judgment behind the data","scenario":"You've shown the executive team a wall of ED metrics. They're waiting for you to tell them what it means and what to worry about. Presence is offering the interpretation, not just the numbers.","task":"Write a 3-sentence read of the data: what it shows, what concerns you, what reassures you.","tips":["Data is your evidence; your read is the value you add.","Say plainly what worries you and what doesn't.","Leaders interpret; analysts only report."],"focus":["impact","precision"]},
    {"id":"presence-doc-senior-24","level":"senior","profession":"doctor","title":"The unwavering safety line","scenario":"Under pressure to reopen elective surgery faster than is safe, you must hold a clear line with the executive team. Your draft wavers, offering to 'find a middle ground' on a safety threshold that shouldn't move.","task":"Write a 2-3 sentence statement that holds the safety line firmly and respectfully.","tips":["Some lines don't have a middle ground — name which this is.","Hold it with a reason, not just a refusal.","Firmness on safety is the core of clinical-leadership presence."],"focus":["impact","clarity"]},
    {"id":"presence-doc-senior-25","level":"senior","profession":"doctor","title":"The one-sentence stance","scenario":"The board chair asks you to sum up your view on the merger in a single sentence for the minutes. Everything you've said needs to compress into one confident line that captures your position.","task":"Write the single sentence that states your position on the merger for the record.","tips":["One sentence forces you to know exactly what you think.","Position first; the sentence should be quotable as your view.","If you can't say it in one line, you haven't decided."],"focus":["impact","concision"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-doc-senior-01","level":"senior","profession":"doctor","title":"Answer the question asked","scenario":"A board member asks: 'Are we going to run out of ICU beds this winter?' Your draft answer launches into the capacity-planning methodology without ever saying yes, no, or 'it depends on what.'","task":"Write a 3-sentence answer that answers the question in the first clause, then supports it.","tips":["Answer first — yes, no, or the honest 'depends on X'.","The methodology is support; it doesn't replace the answer.","A non-answer under pressure reads as evasion, even when it's just habit."],"focus":["clarity","impact"],"placeholder":"Probably not — but only if the flex-unit funding holds."},
    {"id":"pressure-doc-senior-02","level":"senior","profession":"doctor","title":"The hostile budget question","scenario":"In the finance committee, a member snaps: 'Why does your department always blow the budget?' It's hostile and overstated. You need to answer the legitimate core without getting defensive or conceding the exaggeration.","task":"Write a 3-sentence response that addresses the real issue with specifics, not defensiveness.","tips":["Separate the fair question from the hostile framing.","Answer with a specific driver and what you're doing about it.","Defensiveness confirms the attack; specifics defuse it."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-senior-03","level":"senior","profession":"doctor","title":"The 'I don't know' with a path","scenario":"A reporter asks whether the outbreak on 5 East has spread to other units. You genuinely don't yet know. You must say so without alarming anyone or sounding evasive.","task":"Write a 2-3 sentence answer that admits the uncertainty and states how and when you'll know.","tips":["'We don't yet know' is honest; add how you're finding out.","Give a timeframe so it doesn't read as stonewalling.","State what you're doing regardless, to show control."],"focus":["clarity","impact"],"placeholder":"We don't yet have confirmation beyond 5 East. Active surveillance is underway and we'll have results by this evening."},
    {"id":"pressure-doc-senior-04","level":"senior","profession":"doctor","title":"The loaded premise","scenario":"A board member asks: 'Given that morale is at rock bottom, what's your plan?' The premise overstates the case. You need to answer the plan question without accepting or ignoring the loaded frame.","task":"Write a 3-sentence answer that gently corrects the premise and then answers.","tips":["Address the premise briefly — don't let it stand unchallenged or fight it.","Offer the more accurate picture, then pivot to the plan.","Correcting a premise calmly is stronger than ignoring it."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-senior-05","level":"senior","profession":"doctor","title":"The pushback on your recommendation","scenario":"You've recommended closing a rural clinic. A board member pushes hard: 'You're abandoning that community.' It's an emotional challenge to a financial reality. You need to hold the recommendation with empathy and specifics.","task":"Write a 3-4 sentence response that acknowledges the concern and defends the call with specifics.","tips":["Acknowledge the real stake before defending the decision.","Meet emotion with respect, then answer with numbers.","Show you considered the community — that's what earns the hearing."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-senior-06","level":"senior","profession":"doctor","title":"The rapid-fire follow-up","scenario":"After your board presentation, the chair fires three quick questions in a row about the staffing plan. You tend to blend them into one muddled answer. Each deserves a clean, separate response.","task":"For a stacked question — 'How many, by when, and who pays?' — write three crisp one-sentence answers.","tips":["Separate a stacked question into its parts and answer each.","One clean sentence per part beats one tangled paragraph.","Numbering your answers signals control."],"focus":["clarity","concision"]},
    {"id":"pressure-doc-senior-07","level":"senior","profession":"doctor","title":"The question you can't fully answer publicly","scenario":"At a community forum, someone asks for details about a specific patient's death that's under review and legally sensitive. You can't discuss the case, but you must answer respectfully, not stonewall.","task":"Write a 3-sentence response that declines to discuss specifics while showing you take it seriously.","tips":["Explain why you can't discuss it — privacy and review — not just that you won't.","Affirm that it's being taken seriously and reviewed.","Offer the appropriate channel for the family or questioner."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-senior-08","level":"senior","profession":"doctor","title":"The gotcha statistic","scenario":"A board member cites an infection-rate number they read that's worse than yours and asks you to explain the discrepancy on the spot. You suspect their number is stale or differently defined, but you're not certain.","task":"Write a 3-sentence response that engages the number honestly without bluffing.","tips":["Don't bluff a number you're unsure of — say what you'd need to reconcile it.","Offer your figure and its definition, and commit to reconciling.","Honest engagement beats a confident guess that unravels later."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-senior-09","level":"senior","profession":"doctor","title":"The 'why should we trust you' moment","scenario":"After a second quality miss, a board member asks bluntly why they should believe your latest turnaround plan. It's a fair, pointed challenge to your credibility. You need to answer it head-on.","task":"Write a 3-4 sentence answer that meets the credibility challenge with evidence, not assurance.","tips":["Assurances don't answer a credibility challenge — evidence does.","Name what's different this time, concretely.","Acknowledge the prior miss; earned trust starts with honesty about it."],"focus":["impact","clarity"]},
    {"id":"pressure-doc-senior-10","level":"senior","profession":"doctor","title":"The interruption","scenario":"You're mid-answer to the CEO about the divert situation when she cuts in with a sharper, narrower question. You need to abandon your prepared thread and answer the new question directly.","task":"Write the 2-sentence pivot that drops your original point and answers her actual question.","tips":["When the question changes, your answer must — don't finish the old thread.","Pivot cleanly: answer what she just asked, first.","Fighting to finish your point reads as not listening."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-senior-11","level":"senior","profession":"doctor","title":"The speculative 'what if'","scenario":"A reporter asks what you'd do if the outbreak forced closing the entire hospital. It's hypothetical and alarmist. You need to answer the reasonable core without feeding a worst-case headline.","task":"Write a 3-sentence answer that addresses the concern without endorsing the alarming hypothetical.","tips":["Don't repeat the alarming scenario in your answer — it becomes the quote.","Redirect to what you're actually doing and the realistic picture.","Answer the fear underneath the question, not the extreme framing."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-senior-12","level":"senior","profession":"doctor","title":"The physician's angry challenge","scenario":"At the medical staff meeting, a respected surgeon stands and says the new OR scheduling system is 'a disaster you forced on us.' The room watches to see how you handle it. You need to respond without defensiveness or capitulation.","task":"Write a 3-4 sentence response that takes the criticism seriously and holds the decision.","tips":["Acknowledge the specific frustration before defending the change.","Ask for the concrete problem, not the global verdict.","Composure under a public challenge is itself the answer."],"focus":["audience","impact"]},
    {"id":"pressure-doc-senior-13","level":"senior","profession":"doctor","title":"The number you don't have","scenario":"The board chair asks the exact overtime figure for last month. You have a rough sense but not the precise number. You must not invent it, and you must not look unprepared.","task":"Write a 2-sentence answer that gives your best honest estimate flagged as such and commits to the exact figure.","tips":["Flag an estimate as an estimate — never present it as exact.","Give the range you're confident in, then promise the precise number.","A flagged estimate plus a commitment beats a fabricated figure."],"focus":["precision","clarity"],"placeholder":"It was roughly 15 to 18 percent — I'll confirm the exact figure by end of day."},
    {"id":"pressure-doc-senior-14","level":"senior","profession":"doctor","title":"The blame-seeking question","scenario":"After the medication error, an executive asks pointedly 'whose fault was this?' You know the answer is a system failure, not an individual's. You must redirect from blame to cause without seeming to dodge.","task":"Write a 3-sentence answer that redirects from individual blame to the system cause honestly.","tips":["Don't accept the blame frame — but don't sound like you're covering.","Name the system failure specifically; that's the real answer.","Show that fixing the system is the accountable response."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-senior-15","level":"senior","profession":"doctor","title":"The 'yes or no' trap","scenario":"A board member demands a yes-or-no answer to whether the hospital is safe, when the honest answer needs a qualifier. You must give a clear answer without letting the binary force you into a false one.","task":"Write a 2-3 sentence answer that leads with a clear yes or no and adds the essential qualifier.","tips":["Lead with the yes or no — refusing to pick reads as evasion.","Then add the one qualifier that makes it true.","'Yes, and here's the one thing we're watching' respects both the question and the truth."],"focus":["clarity","precision"],"placeholder":"Yes — with one caveat I want you to know about."},
    {"id":"pressure-doc-senior-16","level":"senior","profession":"doctor","title":"The repeated question","scenario":"A council member asks the same question about clinic closures a third time because your first two answers were too hedged. You need to give a plain, direct answer that finally lands.","task":"Write the 2-sentence direct answer you should have given the first time.","tips":["A repeated question means your earlier answer failed — go direct now.","Say the plain thing, no hedging.","If the answer is uncomfortable, being plain is still the fastest path."],"focus":["clarity","concision"]},
    {"id":"pressure-doc-senior-17","level":"senior","profession":"doctor","title":"The challenge to your data","scenario":"In the quality committee, someone says your readmission data 'doesn't match what I'm seeing on the floor.' You need to take the anecdote seriously without abandoning the data, and find the reconciliation.","task":"Write a 3-sentence response that honors the floor experience and holds the data.","tips":["Anecdote and data can both be true — look for how.","Acknowledge the observation, then explain what the data captures.","Offer to look together at the gap — that's leadership, not defense."],"focus":["precision","audience"]},
    {"id":"pressure-doc-senior-18","level":"senior","profession":"doctor","title":"The press question you weren't briefed on","scenario":"A reporter at a scheduled interview pivots to an unrelated staffing lawsuit you weren't prepared to discuss. You need to answer with composure and without saying something you'll regret.","task":"Write a 2-3 sentence holding answer that stays composed and buys time appropriately.","tips":["It's fine to say you'll get them accurate information rather than wing it.","Don't speculate on legal matters on the spot.","Commit to a specific follow-up so the deferral isn't a dodge."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-senior-19","level":"senior","profession":"doctor","title":"The 'you promised' pushback","scenario":"A board member reminds you that you promised the ED metrics would improve by now, and they haven't fully. You need to own the shortfall, explain honestly, and hold credibility.","task":"Write a 3-4 sentence answer that owns the gap, explains it specifically, and states what changes.","tips":["Own the unmet promise directly — evasion here is fatal.","Explain the specific reason without excuse-making.","Follow with the concrete adjustment so it's not just an apology."],"focus":["impact","clarity"]},
    {"id":"pressure-doc-senior-20","level":"senior","profession":"doctor","title":"The trick comparison","scenario":"A board member asks why your hospital's costs are higher than a named competitor's, using a comparison that ignores your case-mix. You need to engage fairly while correcting the flawed comparison.","task":"Write a 3-sentence answer that corrects the comparison and answers the underlying concern.","tips":["Point out what the comparison omits — case-mix, service scope.","Don't dismiss it; the underlying cost concern is fair.","Correct, then answer the real question about cost."],"focus":["precision","clarity"]},
    {"id":"pressure-doc-senior-21","level":"senior","profession":"doctor","title":"The emotional family question at a forum","scenario":"At a community meeting, a grieving family member asks how you'll make sure 'this never happens again.' It's raw and public. You must answer with genuine compassion and a concrete commitment.","task":"Write a 3-sentence answer that responds with empathy and a specific commitment.","tips":["Lead with acknowledgment of their loss — sincerely, briefly.","Follow with a concrete action, not a vague promise.","Empty reassurance wounds; specific commitment consoles."],"focus":["audience","impact"]},
    {"id":"pressure-doc-senior-22","level":"senior","profession":"doctor","title":"The 'just admit it' demand","scenario":"An executive presses you to admit the outbreak response was too slow, when the reality is more mixed. You need to concede what's true and hold what isn't, without seeming to duck accountability.","task":"Write a 3-sentence answer that concedes the valid part and holds the rest with evidence.","tips":["Concede what's genuinely true — it earns credibility for the rest.","Hold the parts that aren't, with specifics.","A calibrated answer beats a full confession or a full denial."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-senior-23","level":"senior","profession":"doctor","title":"The put-on-the-spot vote","scenario":"The board chair asks for your recommendation on a motion you weren't expecting to weigh in on. You have a view but need a moment. You must respond without stalling awkwardly or blurting an ill-formed answer.","task":"Write a 2-3 sentence response that gives your considered position under time pressure.","tips":["Take one beat to frame, then answer — a short pause reads as thought.","Give your position and the one reason behind it.","If you truly need more, say what you'd need and by when."],"focus":["impact","clarity"]},
    {"id":"pressure-doc-senior-24","level":"senior","profession":"doctor","title":"The regulator's direct question","scenario":"During a survey, a regulator asks whether a specific safety practice is consistently followed. The honest answer is 'mostly, with a known gap we're closing.' You must answer truthfully without either overclaiming or alarming.","task":"Write a 3-sentence answer that's honest about the gap and shows active correction.","tips":["Never overclaim to a regulator — the truth surfaces.","State the practice, the honest level of compliance, and the fix underway.","Calibrated honesty with a fix is what regulators reward."],"focus":["precision","clarity"]},
    {"id":"pressure-doc-senior-25","level":"senior","profession":"doctor","title":"The two-part hostile question","scenario":"A board member asks: 'Why did this happen, and why should we believe it won't again?' It's pointed and two-part. You need to answer both parts clearly under the pressure of the room.","task":"Write a 4-sentence answer that addresses the cause and the assurance separately and specifically.","tips":["Answer both parts — dropping one looks evasive.","Cause first, with a specific finding; then the safeguard, concretely.","Assurance backed by a specific change beats 'we'll do better'."],"focus":["clarity","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-doc-senior-01","level":"senior","profession":"doctor","title":"Before and after the flex unit","scenario":"You're persuading the board to fund a permanent flex unit. Your draft is a list of features. It would land far harder as a before-and-after: what a bad day looks like now versus what it would look like with the unit.","task":"Write a 4-sentence before/after that frames the change vividly.","tips":["Contrast is persuasion — paint the current pain, then the relieved future.","Make 'before' concrete: patients in hallways, ambulances waiting.","'After' is the same day, transformed by the thing you're asking for."],"focus":["impact","structure"]},
    {"id":"narrative-doc-senior-02","level":"senior","profession":"doctor","title":"The stake made concrete","scenario":"Your case for the sepsis program cites a relative-risk reduction the board can't feel. The stake is lives, but stated as a statistic it stays abstract. You need to make it concrete without exploiting a patient.","task":"Write 3 sentences that make the stake concrete and human while staying honest.","tips":["Translate the statistic into people: 'that's a dozen patients a year'.","Concrete beats abstract, but stay truthful — no invented cases.","One honest, human frame moves a board more than a percentage."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-03","level":"senior","profession":"doctor","title":"Pre-empt the strongest objection","scenario":"You're proposing to consolidate two labs. The strongest objection is that turnaround times will suffer. Your draft ignores it, which will let a skeptic derail the whole case. You should raise and answer it yourself.","task":"Write 3 sentences that name the turnaround objection and answer it before it's raised.","tips":["Raising the best objection yourself disarms it and builds trust.","State it fairly, then answer with your specific mitigation.","An unaddressed objection grows; an addressed one shrinks."],"focus":["structure","impact"]},
    {"id":"narrative-doc-senior-04","level":"senior","profession":"doctor","title":"The change story for staff","scenario":"You're rolling out a major workflow change nurses will resist. A dry announcement will breed resistance. A narrative — why the old way stopped working, what the new way makes possible — will carry them.","task":"Write a 4-sentence narrative framing the change: what broke, what's changing, what it enables.","tips":["People accept change when they understand why the old way failed.","Name the pain the change solves — theirs, not management's.","End on what it makes possible for them and their patients."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-05","level":"senior","profession":"doctor","title":"The donor's imagined patient","scenario":"You're closing the foundation appeal for the new cancer center. Statistics have numbed the room. One vivid, honest picture of a single patient's changed experience would reopen it.","task":"Write a 3-4 sentence appeal built around one concrete, honest patient journey.","tips":["A single vivid story outpulls a page of statistics.","Keep it honest — a composite is fine; a fabrication is not.","End by connecting their gift to that changed experience."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-06","level":"senior","profession":"doctor","title":"The status quo isn't safe","scenario":"The board is inclined to do nothing about the aging cath lab because change feels risky. You need to reframe: inaction is the real risk. Your draft treats the decision as new-versus-current instead of risk-versus-risk.","task":"Write 3 sentences that reframe doing nothing as the riskier choice.","tips":["Persuasion often means making inaction feel like the active risk.","Name what continues to worsen if nothing changes.","Reframe 'safe default' as 'slow decline'."],"focus":["impact","structure"]},
    {"id":"narrative-doc-senior-07","level":"senior","profession":"doctor","title":"The three-step case","scenario":"You're persuading the executive team to fund a nurse residency program. Your draft is scattered. A tight narrative — the problem, the intervention, the payoff — would carry it.","task":"Write the case as three sentences: the turnover problem, the residency solution, the retention payoff.","tips":["Problem-solution-payoff is a spine any persuasive case can hang on.","Quantify the problem and the payoff; let the solution connect them.","Each step should make the next feel inevitable."],"focus":["structure","impact"]},
    {"id":"narrative-doc-senior-08","level":"senior","profession":"doctor","title":"Persuading the skeptical physician","scenario":"You need buy-in from a senior physician who distrusts administrative initiatives. A top-down pitch will fail. You need to frame the change in terms of what he values — patient outcomes and clinical autonomy.","task":"Write a 3-4 sentence pitch framed around his values, not the administration's goals.","tips":["Persuasion starts from the other person's values, not yours.","Frame the change as serving outcomes and preserving judgment.","Concede what he'll lose honestly — it makes the gain credible."],"focus":["audience","impact"]},
    {"id":"narrative-doc-senior-09","level":"senior","profession":"doctor","title":"The community's before and after","scenario":"You're making the public case for the new urgent-care site. A list of services won't move the community. A picture of what changes for a family that now drives forty minutes for care will.","task":"Write a 3-sentence before/after centered on a local family's experience.","tips":["Local, concrete, human — that's what wins community support.","'Before' is the forty-minute drive; 'after' is care down the street.","Keep the family archetypal and honest, not manipulative."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-10","level":"senior","profession":"doctor","title":"The objection you're avoiding","scenario":"Your proposal to extend hours has an obvious weakness: the staffing to cover it isn't fully solved. You keep hoping no one asks. Addressing it head-on will strengthen the proposal, not sink it.","task":"Write 3 sentences that name the staffing gap honestly and show your plan to close it.","tips":["The objection you're avoiding is the one that will surface — pre-empt it.","Name the gap plainly, then show the plan.","Honesty about a weakness makes the rest more believable."],"focus":["structure","clarity"]},
    {"id":"narrative-doc-senior-11","level":"senior","profession":"doctor","title":"The vision that motivates","scenario":"You're launching the five-year strategic plan to staff. A list of goals won't inspire. A narrative of where the hospital is heading and why it matters to them will. Your draft reads like a to-do list.","task":"Write a 4-sentence narrative that frames the five-year direction as a story staff want to be part of.","tips":["A plan is tasks; a vision is a destination people want to reach.","Connect the direction to what staff care about in their work.","End with their role in getting there — make them protagonists."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-12","level":"senior","profession":"doctor","title":"The cost of delay, dramatized","scenario":"The board keeps deferring the EHR upgrade. You need to make the ongoing cost of delay vivid — the daily friction, the safety risk, the mounting bill. Your draft states the upgrade's benefits abstractly.","task":"Write 3 sentences that make the cost of continued delay concrete and urgent.","tips":["Make delay expensive in the reader's mind — quantify what each month costs.","Concrete daily friction beats abstract future benefit.","Urgency comes from the price of waiting, made real."],"focus":["impact","precision"]},
    {"id":"narrative-doc-senior-13","level":"senior","profession":"doctor","title":"Persuading the CFO with a story","scenario":"You're asking the CFO to fund care coordinators. A spreadsheet alone won't do it. A brief narrative of a high-cost patient who cycles through the ED, and how a coordinator breaks the cycle, makes the numbers land.","task":"Write a 4-sentence case pairing one patient narrative with the financial payoff.","tips":["A story explains why the numbers happen — pair them.","Show the cycle the coordinator breaks, concretely.","Land the financial payoff after the human mechanism."],"focus":["impact","precision"]},
    {"id":"narrative-doc-senior-14","level":"senior","profession":"doctor","title":"The reframe from cost to investment","scenario":"The board sees the wellness program as a cost. You need to reframe it as an investment with a return. Your draft accepts their frame and argues on price, which is a losing position.","task":"Write 3 sentences that reframe the program from cost to investment with a concrete return.","tips":["Fighting on 'cost' concedes the frame — change the frame to 'return'.","Name the return: reduced turnover, lower absenteeism, fewer claims.","A reframe wins arguments that a defense of the price never could."],"focus":["impact","structure"]},
    {"id":"narrative-doc-senior-15","level":"senior","profession":"doctor","title":"The objection from the union, answered","scenario":"You're proposing a scheduling change the union will read as eroding protections. Ignoring their objection guarantees a fight. Naming it and showing what you're protecting builds a path to yes.","task":"Write 3 sentences that name the union's core objection and answer it with a concrete protection.","tips":["Name their real fear — erosion of protections — not a strawman.","Answer with the specific safeguard you're keeping or adding.","Pre-empting their objection turns an adversary into a negotiator."],"focus":["audience","structure"]},
    {"id":"narrative-doc-senior-16","level":"senior","profession":"doctor","title":"The turnaround narrative","scenario":"Your department has recovered from a rough year, and you're presenting to the board. A list of metrics won't convey the arc. A narrative — where you were, what you changed, where you are — will make the recovery felt.","task":"Write a 4-sentence turnaround narrative: the low point, the intervention, the current state, the trajectory.","tips":["A recovery is a story with a turning point — name the turning point.","Be honest about the low; it makes the recovery credible.","End on trajectory, so the board sees momentum, not just a snapshot."],"focus":["structure","impact"]},
    {"id":"narrative-doc-senior-17","level":"senior","profession":"doctor","title":"The stakes for the community","scenario":"You're making the case to keep the money-losing obstetrics service open, on community-need grounds. The stake is that families would have to travel for delivery. You need to make that stake vivid to a finance-focused board.","task":"Write 3 sentences that make the community stake concrete against the financial pressure.","tips":["Name what the community loses in concrete terms — the nearest alternative and its distance.","Acknowledge the financial reality, then weigh the human stake against it.","Make the board feel the choice, not just read the deficit."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-18","level":"senior","profession":"doctor","title":"Pre-empting the 'we tried this' objection","scenario":"You're proposing a patient-flow initiative similar to one that failed three years ago. The strongest objection is 'we tried this and it didn't work.' You must name that history and show what's different.","task":"Write 3 sentences that acknowledge the prior failure and show what's genuinely different now.","tips":["'We tried this' is disarmed only by owning the prior attempt.","Name specifically why it failed and what's changed.","Honesty about the past failure earns the benefit of the doubt."],"focus":["structure","clarity"]},
    {"id":"narrative-doc-senior-19","level":"senior","profession":"doctor","title":"The recruitment story","scenario":"You're recruiting a division chief and need to sell the role. A list of the hospital's assets won't move a top candidate. A narrative of what she could build here — the arc from where the division is to where she'd take it — will.","task":"Write a 4-sentence pitch framed as the story of what she could build.","tips":["Top candidates buy a mission, not a job description.","Frame the current state as raw potential she'd shape.","Make her the protagonist of the division's next chapter."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-20","level":"senior","profession":"doctor","title":"The safety case, made urgent","scenario":"You're asking for funding for a new medication-safety system. The current process rarely fails, so complacency is the enemy. You need a narrative that makes a rare-but-catastrophic risk feel present without fear-mongering.","task":"Write 3 sentences that convey the low-probability, high-severity risk persuasively and honestly.","tips":["Rare risks need the severity made vivid without exaggerating frequency.","Frame it as buying insurance against the unbearable.","Honesty about probability keeps you credible; severity carries the case."],"focus":["impact","precision"]},
    {"id":"narrative-doc-senior-21","level":"senior","profession":"doctor","title":"The board's 'why now'","scenario":"Your proposal to expand behavioral-health capacity is sound but perennial. The board will ask 'why now?' You need a narrative that makes this the moment — a convergence of need, opportunity, and cost of waiting.","task":"Write 3 sentences that answer 'why now' with a compelling convergence.","tips":["'Why now' is answered by what's changed or what closes soon.","Name the window — funding, need spike, a partner ready.","Urgency without a real 'why now' reads as manufactured."],"focus":["impact","structure"]},
    {"id":"narrative-doc-senior-22","level":"senior","profession":"doctor","title":"The morale-rebuilding message","scenario":"After a demoralizing year, you're addressing the department. A cheerful pivot would ring false. A narrative that honors the hardship and points honestly to what's ahead will actually rebuild belief.","task":"Write a 4-sentence message that honors the hard year and frames a credible path forward.","tips":["Acknowledge the difficulty specifically — glossing it loses the room.","Point to concrete evidence that things are turning.","Frame the team as having endured, not just suffered."],"focus":["audience","impact"]},
    {"id":"narrative-doc-senior-23","level":"senior","profession":"doctor","title":"The objection from finance, pre-empted","scenario":"You're proposing a clinical program the finance committee will call unaffordable. The strongest objection is the operating cost. You need to name it and show the offsetting value before they raise it.","task":"Write 3 sentences that raise the affordability objection yourself and answer it.","tips":["Name the cost objection first — it signals you've done the math.","Answer with the offset: avoided costs, new revenue, or downstream value.","Owning the hard number builds trust in the rest of your case."],"focus":["structure","precision"]},
    {"id":"narrative-doc-senior-24","level":"senior","profession":"doctor","title":"The legacy frame for a big gift","scenario":"You're asking a major donor to fund the hospital's largest project in a decade. The persuasion is about legacy — what their name enables for a generation. Your draft focuses on the building's specifications.","task":"Write a 3-4 sentence appeal framed around the donor's legacy and lasting impact.","tips":["Major gifts are about meaning, not square footage.","Frame the gift as a legacy that outlives them.","Connect their name to the generations of patients it will serve."],"focus":["impact","audience"]},
    {"id":"narrative-doc-senior-25","level":"senior","profession":"doctor","title":"The all-in-one persuasive close","scenario":"You're closing your board presentation on the capital plan. You need one tight passage that frames the change, makes the stake concrete, and pre-empts the cost objection — the whole persuasive toolkit in a few sentences.","task":"Write a 4-5 sentence close that frames the before/after, names the stake, and answers the cost objection.","tips":["A strong close does three jobs: contrast, stake, objection.","Lead with the after you're building toward.","End by turning the cost into the price of the stake you named."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-doc-senior-01","level":"senior","profession":"doctor","title":"The program closure, front-loaded","scenario":"You must tell the inpatient rehab staff their unit is closing in ninety days. Your draft opens with budget context and eases toward the news. That leaves people scanning anxiously for the point they already fear.","task":"Write a 3-4 sentence opening that delivers the closure decision plainly in the first sentence.","tips":["Front-load the hard news — making people wait for it is its own cruelty.","State the decision and the timeline first, clearly.","Support and next steps come after the news lands, not before."],"focus":["clarity","impact"],"placeholder":"I need to share a difficult decision: the inpatient rehab unit will close on March 31."},
    {"id":"hard-doc-senior-02","level":"senior","profession":"doctor","title":"The clean 'no' to a chief","scenario":"A department chief has asked repeatedly for a new position you can't fund. Your past replies were soft enough that he keeps asking. He deserves a clear, respectful no that ends the loop.","task":"Write a 3-sentence response that says no clearly, gives the reason, and names what could change it.","tips":["A soft no that invites re-asking wastes everyone's time.","Say no plainly, then the real reason, then the honest condition for reconsidering.","Clarity is the respect here, not the cushioning."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-03","level":"senior","profession":"doctor","title":"Behavior, impact, ask","scenario":"A talented surgeon is dismissive to OR nurses, and it's affecting the team. You need to give feedback that names the behavior, its impact, and a clear ask — without attacking his character.","task":"Write a 3-4 sentence feedback message using behavior, impact, and ask.","tips":["Describe the specific behavior, not a character judgment.","Name the impact concretely — on the team, on safety.","End with a clear, doable ask, not a vague 'be nicer'."],"focus":["clarity","precision"]},
    {"id":"hard-doc-senior-04","level":"senior","profession":"doctor","title":"The layoff notification","scenario":"You must inform an administrator that their role is being eliminated in the restructure. This is one of the hardest messages you deliver. It must be clear, humane, and free of false comfort.","task":"Write a 3-4 sentence opening for the conversation that delivers the news directly and humanely.","tips":["Say it plainly and early — dragging it out is unkind.","No false hope, no burying it in restructure jargon.","Follow immediately with the concrete support available."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-05","level":"senior","profession":"doctor","title":"The disclosure to a family","scenario":"You're overseeing the disclosure to a family that a preventable error harmed their relative. Honesty and compassion are both required, and evasion would be catastrophic. You need to lead with the truth and the apology.","task":"Write a 3-4 sentence opening that discloses the error honestly and offers a genuine apology.","tips":["Lead with what happened and that it was preventable — don't hedge.","A genuine apology is specific, not a legalistic 'regret'.","Commit to the review and to keeping them informed."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-06","level":"senior","profession":"doctor","title":"The performance conversation","scenario":"A division chief's performance has slipped and it's affecting the department. You need to open a serious conversation without ambushing or softening past the point of clarity. The message must register as serious.","task":"Write a 3-sentence opening that names the concern seriously and specifically.","tips":["Vague concern doesn't register — be specific about what's slipping.","Serious but not hostile; this is a professional, not personal, conversation.","Name the stakes so the seriousness is unmistakable."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-07","level":"senior","profession":"doctor","title":"The 'no' to the board's pet idea","scenario":"A board member is championing a service line the data says won't work. You must tell the board no, respectfully, against a favored idea. Softening it would let the bad idea live.","task":"Write a 3-sentence message that declines the idea clearly with the evidence.","tips":["Respect the board member while being clear the idea doesn't hold.","Lead with the evidence-based no, not with praise for the enthusiasm.","A clear no now prevents a costly yes later."],"focus":["clarity","precision"]},
    {"id":"hard-doc-senior-08","level":"senior","profession":"doctor","title":"The budget cut, delivered whole","scenario":"You must tell your department that next year's budget is cut and some initiatives will stop. Your draft dribbles the bad news across paragraphs. Delivering it whole, up front, is kinder than a slow reveal.","task":"Write a 3-sentence opening that states the cut and its main consequence directly.","tips":["Give the whole hard picture at once — a slow reveal prolongs the dread.","State the cut and the one biggest consequence together.","Then, and only then, what's protected and what's next."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-09","level":"senior","profession":"doctor","title":"The apology without excuses","scenario":"After the EHR outage disrupted care, you're addressing staff. Your draft mixes the apology with a defense of the IT decisions that led to it. The defensiveness undercuts the apology.","task":"Write a 3-sentence message that apologizes cleanly, without the defensive explanation.","tips":["An apology tangled with excuses isn't an apology.","Own the disruption plainly; save the root-cause analysis for later.","Commit to the fix without relitigating the cause here."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-10","level":"senior","profession":"doctor","title":"The denied promotion","scenario":"A physician you value applied for a leadership role and didn't get it. You must tell them, honestly and kindly, and keep them engaged. Vagueness about why would frustrate more than the no itself.","task":"Write a 3-4 sentence message that delivers the no, gives honest reasons, and affirms their value.","tips":["The no needs a real reason, or it festers.","Be specific about what would strengthen a future bid.","Affirm their value genuinely — but after the clear no, not instead of it."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-11","level":"senior","profession":"doctor","title":"The safety stand-down","scenario":"A serious safety event means you're suspending a procedure across the department pending review. Physicians will be frustrated. You must deliver the stand-down clearly and hold firm on why.","task":"Write a 3-sentence message announcing the suspension and the reason firmly.","tips":["Lead with the suspension and its effective time — no ambiguity.","Give the safety reason plainly; it's the whole justification.","Firm and clear; a hedged safety message invites workarounds."],"focus":["clarity","impact"],"placeholder":"Effective immediately, we're suspending all elective use of the device pending review."},
    {"id":"hard-doc-senior-12","level":"senior","profession":"doctor","title":"The 'we missed the target' to the board","scenario":"You must tell the board the department missed its quality target. Your draft opens with everything that went right, delaying the miss. The board will feel managed. Lead with the miss.","task":"Write a 3-sentence board update that states the miss first, then the context.","tips":["Front-load the miss — the board hates being softened up.","State the number missed and by how much.","Context and corrective plan follow the honest headline."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-13","level":"senior","profession":"doctor","title":"The colleague overstepping","scenario":"A fellow executive has been making decisions that belong in your domain. You need to raise it directly and preserve the working relationship. Avoiding it lets the pattern continue; attacking damages the partnership.","task":"Write a 3-sentence message that names the overstep and proposes a clear boundary.","tips":["Name the specific instances, not a general grievance.","Frame it as clarifying lanes, not accusing.","Propose the boundary concretely so it's actionable."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-14","level":"senior","profession":"doctor","title":"The hard truth to the CEO","scenario":"The CEO's favored expansion plan has a flaw the data makes clear, and no one has told her. As the clinical leader, you must. Softening it or staying silent would be a failure of your role.","task":"Write a 3-4 sentence message that tells the CEO the hard truth directly and constructively.","tips":["Speaking truth to the CEO is your job — do it plainly.","Lead with the flaw and the evidence, respectfully.","Offer a constructive path so it's counsel, not just criticism."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-15","level":"senior","profession":"doctor","title":"The end-of-contract conversation","scenario":"A locum's contract won't be renewed because of performance concerns. You must tell them clearly, document it fairly, and avoid false reassurance. A muddled message risks both unfairness and legal exposure.","task":"Write a 3-sentence message that delivers the non-renewal clearly and professionally.","tips":["State the non-renewal and the effective date directly.","Keep it factual and professional — no false 'it's not you'.","Reference the specific concern documented, not vague dissatisfaction."],"focus":["clarity","precision"]},
    {"id":"hard-doc-senior-16","level":"senior","profession":"doctor","title":"The public statement after a death","scenario":"A patient death has drawn press attention and you must issue a statement. It must be compassionate, honest about the review, and free of anything that reads as evasion or premature conclusion.","task":"Write a 3-4 sentence statement that expresses compassion and commits to a transparent review.","tips":["Lead with genuine compassion for the family.","Commit to a thorough review without pre-judging its outcome.","Avoid both admission of fault and defensive denial — neither serves anyone yet."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-17","level":"senior","profession":"doctor","title":"The 'your unit is being merged'","scenario":"You must tell a unit manager her unit is being merged into another, and she'll report to someone else. It's a demotion in effect. She deserves the news straight, with dignity.","task":"Write a 3-4 sentence message that delivers the merger and reporting change directly and respectfully.","tips":["Deliver the structural change plainly — don't dress a demotion as opportunity.","Acknowledge honestly what changes for her.","Show respect through clarity and a real conversation about her role."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-18","level":"senior","profession":"doctor","title":"The overrun you own","scenario":"Your department caused a significant budget overrun and you must tell the CFO. Your draft spreads the responsibility thin. Owning it cleanly builds more trust than diffusing it.","task":"Write a 3-sentence message that owns the overrun, states the number, and names the correction.","tips":["Own it — diffused responsibility reads as evasion.","State the number plainly; the CFO already knows roughly.","Follow ownership with the specific corrective action."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-19","level":"senior","profession":"doctor","title":"The feedback to a high performer","scenario":"A top physician-leader has a blind spot that's hurting a project. High performers rarely get hard feedback, so it must be specific and clearly meant to help, not to diminish.","task":"Write a 3-4 sentence feedback message: the behavior, its impact on the project, and the ask.","tips":["High performers deserve candor — vagueness insults their competence.","Anchor in the specific behavior and its project impact.","Frame the ask as raising an already high ceiling."],"focus":["clarity","precision"]},
    {"id":"hard-doc-senior-20","level":"senior","profession":"doctor","title":"The 'we're going on divert' to the community","scenario":"The hospital must announce it's periodically on ambulance divert, which sounds alarming to the public. You must be honest about the strain without causing panic or eroding trust.","task":"Write a 3-4 sentence public message that's honest about divert and reassuring about safety.","tips":["Explain divert plainly — hiding it erodes trust when it surfaces.","Reassure specifically: emergencies are still cared for, here's how.","Honesty plus a clear safety net calms more than silence does."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-21","level":"senior","profession":"doctor","title":"The 'no' to a generous but wrong gift","scenario":"A major donor wants to fund equipment the hospital doesn't need over a critical need it won't fund. You must decline the mismatch gracefully and redirect, risking the relationship if handled poorly.","task":"Write a 3-4 sentence message that declines the specific gift and redirects to the real need.","tips":["Honor the generosity before redirecting it.","Be honest about why the equipment isn't the priority.","Offer the real need as an even better use of their gift."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-22","level":"senior","profession":"doctor","title":"The accountability after a near-miss","scenario":"A near-miss revealed a team failed to follow protocol. You must address the team firmly about accountability while keeping a just-culture tone that doesn't drive future events underground.","task":"Write a 3-4 sentence message that holds accountability and preserves psychological safety.","tips":["Distinguish the system fix from individual accountability clearly.","Be firm about the standard without blaming into silence.","Reinforce that reporting near-misses is what you want — and reward it."],"focus":["clarity","audience"]},
    {"id":"hard-doc-senior-23","level":"senior","profession":"doctor","title":"The pay-freeze announcement","scenario":"You must tell staff there will be no raises this year. Your draft buries it under financial context. Staff will feel it whenever it comes; leading with it, honestly, respects them more.","task":"Write a 3-sentence announcement that states the pay freeze first, then the honest reason.","tips":["Lead with the freeze — people brace less when they're not blindsided.","Give the honest financial reason briefly.","Acknowledge the impact on people; don't pretend it's minor."],"focus":["clarity","impact"]},
    {"id":"hard-doc-senior-24","level":"senior","profession":"doctor","title":"The recusal you must require","scenario":"A senior physician has a conflict of interest on a vendor decision and must step back. He won't like being told. You must require the recusal clearly while preserving his standing.","task":"Write a 3-sentence message that requires the recusal firmly and respectfully.","tips":["State the recusal as a requirement, not a request, but respectfully.","Ground it in policy and the appearance of conflict, not his intent.","Affirm his integrity while holding the line."],"focus":["clarity","precision"]},
    {"id":"hard-doc-senior-25","level":"senior","profession":"doctor","title":"The whole hard message, well built","scenario":"You must tell the department that a beloved service is closing, staff will be reassigned, and it takes effect in sixty days. This is the hardest kind of message — clear news, real impact, humane delivery, all in one.","task":"Write a 4-5 sentence message that front-loads the news, names the impact honestly, and points to support.","tips":["News first, in the first sentence — everything else follows it.","Name the human impact plainly; don't minimize it.","End with concrete support and the next conversation, so people aren't left in freefall."],"focus":["clarity","impact"]}
  ],
  "putting-it-together": [
    {"id":"together-doc-senior-01","level":"senior","profession":"doctor","title":"The board pre-read, whole","scenario":"You have twenty minutes to write the one-page board pre-read on the quarter. It must lead with the point, structure the supporting material, cut the padding, and end with the ask. Everything you've practiced, in one artifact under time pressure.","task":"Write the full one-page pre-read: headline, three supporting points, and the ask, in 6-8 sentences.","tips":["Headline first, ask last, three clean points between.","Cut anything that doesn't serve the board's decision.","Read it once as a busy board member — does it work in ninety seconds?"],"focus":["structure","impact"]},
    {"id":"together-doc-senior-02","level":"senior","profession":"doctor","title":"Same news, three channels","scenario":"The MRI suite opening is delayed. You must convey it to the CEO (email), the staff (memo), and the public (web notice). Each needs a different register, length, and emphasis, though the fact is the same.","task":"Write the one-sentence version for each of the three channels, matched to its audience.","tips":["The fact is constant; the framing changes with the reader.","CEO wants the impact on plans; staff want what changes for them; public wants reassurance.","Register and length are part of the message, not decoration."],"focus":["audience","concision"]},
    {"id":"together-doc-senior-03","level":"senior","profession":"doctor","title":"The crisis message under real constraint","scenario":"A serious safety event just occurred. In ten minutes you must write the executive notification: what happened, current status, immediate actions, and next update time. Clear, structured, calm, complete — under real pressure.","task":"Write the 4-5 sentence notification integrating BLUF, structure, and precision.","tips":["Lead with what happened and the patient's status now.","Structure the rest: actions taken, actions pending, next update.","Calm and complete beats fast and frantic."],"focus":["structure","clarity"],"placeholder":"At 2:15pm a serious safety event occurred on 6 West; the patient is stable."},
    {"id":"together-doc-senior-04","level":"senior","profession":"doctor","title":"The persuasive budget memo","scenario":"You're writing the memo that must win funding for the nurse residency program. It needs a clear ask, a persuasive narrative, precise numbers, and a pre-empted objection — the full toolkit in one document.","task":"Write a 6-8 sentence memo: the ask, the before/after case, the numbers, and the answered objection.","tips":["Lead with the ask, then build the persuasive case beneath it.","One vivid frame, one hard number, one pre-empted objection.","End by restating the ask with the strongest reason attached."],"focus":["impact","structure"]},
    {"id":"together-doc-senior-05","level":"senior","profession":"doctor","title":"Edit like a reader","scenario":"You've drafted the all-staff message on the reorganization. Before sending, you must read it as the anxious staff member who'll receive it, and edit for what they actually need to know first.","task":"Rewrite your draft's opening two sentences as the reader-first version, cutting what serves you not them.","tips":["Read your own draft as its most anxious reader.","Cut the sentences that reassure you but not them.","Lead with their question — 'what happens to me?' — answered."],"focus":["audience","clarity"]},
    {"id":"together-doc-senior-06","level":"senior","profession":"doctor","title":"The regulator response, complete","scenario":"You must respond to three regulatory findings. The response needs structure by finding, precise remediation with dates, an owned accountability, and a clean register — the full range in a high-stakes document.","task":"Write the response's opening commitment plus a structured one-sentence remediation for each finding.","tips":["Open with clear, owned accountability.","One parallel-structured remediation per finding: fix, date, verification.","Precise and complete; a regulator reads for exactly this."],"focus":["structure","precision"]},
    {"id":"together-doc-senior-07","level":"senior","profession":"doctor","title":"The town hall open, integrated","scenario":"You're opening the all-staff town hall covering four topics after a hard quarter. You need a governing theme, a signposted structure, an honest acknowledgment of the difficulty, and presence — all in the first ninety seconds.","task":"Write a 5-6 sentence town hall opening that sets the theme, signposts the structure, and reads with presence.","tips":["One theme ties the four topics; name it up front.","Signpost the structure so people can follow.","Acknowledge the hard quarter honestly, then lead."],"focus":["structure","impact"]},
    {"id":"together-doc-senior-08","level":"senior","profession":"doctor","title":"The email you'll be judged on","scenario":"You're replying to the board chair's pointed question about winter readiness. This single email shapes her confidence in you. It must answer directly, structure the support, be precise, and close cleanly.","task":"Write the 5-6 sentence reply: direct answer, three supporting points, precise numbers, clean close.","tips":["Answer the question in the first sentence — direct, not hedged.","Three supporting points, each with a number.","Close with what you need from her, if anything, or 'no action needed'."],"focus":["clarity","precision"]},
    {"id":"together-doc-senior-09","level":"senior","profession":"doctor","title":"The hard message, fully built","scenario":"You must tell the department a service is closing. This integrates everything: front-loaded news, clear structure, honest impact, precise timeline, humane register, and a path forward — one message that has to land right.","task":"Write the full 5-6 sentence message integrating BLUF, structure, precision, and humane delivery.","tips":["News in sentence one; timeline precise; impact honest.","Structure the middle: what, when, what it means for you.","End with concrete support and the next conversation."],"focus":["clarity","structure"]},
    {"id":"together-doc-senior-10","level":"senior","profession":"doctor","title":"The elevator answer to the CEO","scenario":"The CEO catches you between meetings: 'Give me the state of the ED in thirty seconds.' You must integrate BLUF, structure, and precision into a spoken answer that fits the time and the channel.","task":"Write the 3-4 sentence spoken answer: headline, the two numbers that matter, the one risk.","tips":["Thirty seconds is a spec — lead with the headline.","Two numbers, not ten; the ones she'd repeat.","End with the single risk you'd want her aware of."],"focus":["concision","impact"]},
    {"id":"together-doc-senior-11","level":"senior","profession":"doctor","title":"The strategy one-pager","scenario":"The board wants the service-line strategy on one page. It must have a governing idea, three thrusts, precise targets, and a persuasive frame — the whole discipline compressed onto a single page.","task":"Write the one-pager: governing sentence, three thrusts with a target each, and a one-sentence 'why now'.","tips":["Governing idea at the top; three thrusts beneath.","Attach a precise target to each thrust.","Close with a 'why now' that makes the page urgent."],"focus":["structure","precision"]},
    {"id":"together-doc-senior-12","level":"senior","profession":"doctor","title":"The press statement, complete","scenario":"After a serious incident, you must issue a public statement. It must be compassionate, honest, precise about the review process, clear in register, and free of anything that reads as evasion — a genuinely hard integration.","task":"Write a 4-5 sentence statement integrating compassion, honesty, precision, and clean register.","tips":["Compassion first, then the commitment to review.","Precise about process without pre-judging outcome.","Every word will be quoted — no evasion, no admission it's too early to make."],"focus":["audience","clarity"]},
    {"id":"together-doc-senior-13","level":"senior","profession":"doctor","title":"The reorg announcement, all of it","scenario":"You're announcing a reorganization to staff. It must lead with clarity, structure by who's affected, be honest about hard changes, read with presence, and reduce anxiety — every skill at once.","task":"Write a 5-6 sentence announcement that leads clearly, structures by group, and delivers hard parts honestly.","tips":["Lead with the one governing message about the change.","Structure so each group finds its answer fast.","Be honest about what's hard; presence means not sugar-coating."],"focus":["structure","audience"]},
    {"id":"together-doc-senior-14","level":"senior","profession":"doctor","title":"The finance committee case, integrated","scenario":"You're making the case for the CT scanner to the finance committee. It must translate clinical value into financial terms, lead with the recommendation, use precise numbers, and pre-empt the cost objection — a full-toolkit argument.","task":"Write a 6-sentence case: recommendation, financial frame, precise payback, pre-empted objection.","tips":["Recommendation first, in the committee's financial language.","Translate clinical benefit into throughput and recaptured volume.","Give the precise payback and answer the affordability objection."],"focus":["audience","precision"]},
    {"id":"together-doc-senior-15","level":"senior","profession":"doctor","title":"The weekend handoff, tight","scenario":"You're handing off to the on-call executive. The note must lead with the one live issue, structure the rest, be precise about triggers and contacts, and cut everything routine — clarity under the constraint of brevity.","task":"Write a 4-5 sentence handoff: the live issue and its trigger first, then two structured watch-items.","tips":["Live issue first — if they read one line, that's it.","Precise triggers: what to do and when to act.","Cut routine items; a handoff is exceptions, not status."],"focus":["structure","concision"]},
    {"id":"together-doc-senior-16","level":"senior","profession":"doctor","title":"The donor appeal, whole","scenario":"You're writing the case for support for the NICU expansion. It must be audience-tuned to donors, built as a narrative, precise about impact, and free of jargon — the full craft aimed at one generous reader.","task":"Write a 5-6 sentence appeal: human frame, before/after, one precise impact number, legacy close.","tips":["Open in the family's experience, not the capacity metric.","Before/after, with one honest, precise number.","Close on legacy — what their gift makes possible for years."],"focus":["audience","impact"]},
    {"id":"together-doc-senior-17","level":"senior","profession":"doctor","title":"The answer that must do everything","scenario":"At the board meeting, a director asks a hard, multi-part question about a quality miss under scrutiny. Your spoken answer must be direct, structured, precise, own the miss, and hold credibility — every skill live, in real time.","task":"Write a 5-6 sentence spoken answer that answers directly, structures the cause and fix, and owns the miss.","tips":["Answer the core question first, plainly.","Structure: what happened, why, what changes.","Own the miss; a defended miss loses the room."],"focus":["clarity","structure"]},
    {"id":"together-doc-senior-18","level":"senior","profession":"doctor","title":"The memo that survives forwarding","scenario":"Your memo recommending the staffing change will be forwarded to people who weren't copied and lack context. It must be self-contained, lead with the point, structure cleanly, and need no backstory — written for readers you can't see.","task":"Write a 5-6 sentence memo that stands alone for a reader with zero prior context.","tips":["Assume the reader has no backstory — supply just enough.","Lead with the recommendation; structure the support.","Self-contained means no 'as we discussed' — spell it out briefly."],"focus":["structure","clarity"]},
    {"id":"together-doc-senior-19","level":"senior","profession":"doctor","title":"The community forum open","scenario":"You're opening a public forum on the hospital's capacity strain. It must translate operational reality into plain language, structure the message, project calm presence, and set an honest tone — everything, in front of a wary public.","task":"Write a 5-6 sentence forum opening that's plain-language, structured, and honest without alarming.","tips":["Translate every metric into what a patient would experience.","Structure so the public can follow the causal story.","Honest about strain, clear about the safety net — calm presence throughout."],"focus":["audience","impact"]},
    {"id":"together-doc-senior-20","level":"senior","profession":"doctor","title":"The recommendation email, polished","scenario":"You're recommending the hospital not pursue an acquisition everyone else favors. The email must own the unpopular position, structure the reasoning, use precise evidence, and pre-empt the excitement-driven objection — integrated and confident.","task":"Write a 5-6 sentence email that owns the position, structures the evidence, and answers the objection.","tips":["Own the unpopular recommendation in sentence one.","Structure the reasoning; lead with the strongest evidence.","Pre-empt the 'but everyone's excited' objection with the risk they're underweighting."],"focus":["impact","structure"]},
    {"id":"together-doc-senior-21","level":"senior","profession":"doctor","title":"The all-clear that rebuilds trust","scenario":"After a prolonged outage that eroded confidence, you're sending the all-clear. It must lead with the restored status, be precise about what's recovered, acknowledge the disruption honestly, and read with steadying presence.","task":"Write a 4-5 sentence all-clear that leads with status, is precise about recovery, and rebuilds confidence.","tips":["Lead with the restored status and time.","Precise about what's fully back and what's still catching up.","Acknowledge the disruption briefly; steadiness rebuilds trust."],"focus":["clarity","impact"]},
    {"id":"together-doc-senior-22","level":"senior","profession":"doctor","title":"The board resolution, edited","scenario":"You've drafted the board resolution approving the capital plan. It must be precise, unambiguous, appropriately formal in register, and cut of every spare word — the final edit on a document of record.","task":"Write the 3-4 sentence resolution: precise, formal, and free of any spare clause.","tips":["A resolution is a record — every word must be defensible.","Formal register, but no bloat; precision is the point.","Cut every clause that doesn't change the meaning."],"focus":["precision","concision"]},
    {"id":"together-doc-senior-23","level":"senior","profession":"doctor","title":"The mixed-audience briefing","scenario":"You're briefing a room with the board, physicians, and community reps together on the strategic plan. The message must serve one primary audience while not alienating the others, structured and precise — a real integration challenge.","task":"Write a 5-6 sentence briefing that picks a primary audience and structures the message for them without losing the others.","tips":["Pick a primary audience — you can't fully serve three at once.","Structure for them; give the others a clear line each.","Precise and plain so no group is lost."],"focus":["audience","structure"]},
    {"id":"together-doc-senior-24","level":"senior","profession":"doctor","title":"The 60-second video script","scenario":"You're recording a 60-second video for all staff about the year ahead. It must be spoken-friendly, lead with the point, be structured, project presence, and stay tight — every skill, in a spoken medium.","task":"Write the 5-6 sentence script: a clear opening point, three short movements, and a confident close.","tips":["Written to be spoken — short sentences, natural rhythm.","Lead with the one thing you want them to remember.","Three movements, confident close; presence carries a video."],"focus":["structure","impact"]},
    {"id":"together-doc-senior-25","level":"senior","profession":"doctor","title":"The capstone board presentation","scenario":"You're delivering the year-end board presentation: the department's performance, a hard miss, a bold ask for next year. It must integrate everything — BLUF, structure, precision, presence, persuasion, and honest hard news — in one high-stakes deliverable.","task":"Write the 6-8 sentence spine: opening headline, structured performance, the honest miss, the persuasive ask, and a confident close.","tips":["Open with the year's headline; structure the body into clear movements.","Deliver the miss honestly, mid-presentation, without burying it.","Build the ask persuasively and close with presence — the last line is what they carry."],"focus":["structure","impact"]}
  ],
};
